/// \brief Indicates kinematic vectors in the Radial-Transverse-Normal (RTN) reference
/// frame, also known as the Radial, In-Track, Cross-Track (RIC) reference
/// frame. The Radial basis vector is aligned with the position vector. The
/// Normal basis vector is aligned with the angular momentum direction (which
/// is the orbit normal direction). The Transverse basis vector is in the
/// direction of N x R to complete the right-handed triad.
/// uci_version: 002.001.000.000
struct RTN_KinematicsType {
    /// \brief Indicates the time when the kinematic data is valid.
    /// xsd type: DateTimeType (pattern .+Z)
    std::string epoch = {};
    /// \brief Indicates a position vector in the RTN reference frame.
    RTN_PositionType position = {};
    /// \brief Indicates a velocity vector in the RTN reference frame.
    RTN_VelocityType velocity = {};
    /// \brief Indicates an acceleration vector in the RTN reference frame.
    tl::optional<RTN_AccelerationType> acceleration;  // optional
    /// \brief Indicates the attitude in the RTN reference frame.
    tl::optional<QuaternionType> attitude;  // optional
    /// \brief The covariance matrix along with its associated category that defines the
    /// elements represented in the covariance matrix in the RTN reference frame.
    /// See the individual category enumerations for detailed explanations.
    tl::optional<CovarianceMatrixType> covariance;  // optional
};

/// \brief Indicates kinematics for an orbital object, expressed in the
/// Radial-Transverse-Normal Reference System, relative to another orbital
/// object whose kinematics are relative to a celestial object.
/// uci_version: 002.000.000.000
struct OrbitalKinematicsObjectRelativeType {
    /// \brief Indicates kinematic vectors for an orbital object, expressed in the
    /// Radial-Transverse-Normal Reference System, relative to the orbital object
    /// indicated by the sibling ReferenceObjectKinematics element.
    RTN_KinematicsType relative_object_kinematics = {};
    /// \brief Indicates kinematic vectors for an orbital object that serves as the
    /// reference for the relative kinematics given in the sibling
    /// RelativeObjectKinematics element.
    OrbitalKinematicsStandardFrameChoiceType reference_object_kinematics = {};
    /// \brief Indicates the unique ID of the object whose kinematics are described in the
    /// sibling ReferenceObjectKinematics element.
    tl::optional<AssetType> reference_asset;  // optional
};

/// \brief Indicates the kinematics expressed in one of several orbital kinematics
/// standards.
/// uci_version: 002.000.000.000
struct OrbitalKinematicsChoiceType {
    // oneof choice
    /// \brief Indicates kinematics expressed in terms of a standard frame centered on a
    /// celestial object.
    tl::optional<OrbitalKinematicsStandardFrameChoiceType> standard_frame;
    /// \brief Indicates kinematics expressed relative to a reference object that is in
    /// orbit around a celestial object.
    tl::optional<OrbitalKinematicsObjectRelativeType> orbiting_object_relative;
};

/// \brief Acceleration relative to WGS-84 ellipsoid.
/// uci_version: 000.000.000.000
struct Acceleration3D_Type {
    /// \brief The acceleration component along the true north direction.
    /// xsd type: AccelerationType
    double north_acceleration = 0.0;
    /// \brief The acceleration component along the east direction.
    /// xsd type: AccelerationType
    double east_acceleration = 0.0;
    /// \brief The acceleration component along the down direction.
    /// xsd type: AccelerationType
    double down_acceleration = 0.0;
    /// \brief Indicates the date and time at which the acceleration data was measured,
    /// last known to be correct and/or predicted to occur.
    /// xsd type: DateTimeType (pattern .+Z)
    std::string timestamp = {};  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 001.001.002.002
struct Point2D_ReportedType {
    double latitude = 0.0;  // from Point2D_Type
    double longitude = 0.0;  // from Point2D_Type
    tl::optional<double> altitude;  // from Point2D_Type  // optional
    tl::optional<AltitudeRangeType> altitude_range;  // from Point2D_Type  // optional
    tl::optional<AltitudeReferenceEnum> altitude_reference;  // from Point2D_Type  // optional
    std::string timestamp = {};  // from Point2D_Type  // optional
    /// \brief Difference in meters between the MSL and HAE altitudes of an object. MSL +
    /// HAE_Adjustment = HAE, per MIL-STD-6016.
    /// xsd type: DistanceOffsetType
    tl::optional<double> hae_adjustment;  // optional
    /// \brief Source of the reported altitude.
    tl::optional<AltitudeSourceEnum> altitude_source;  // optional
    /// \brief Expresses track depth by description of horizontal planes at or below Mean
    /// Sea Level (MSL)
    tl::optional<DepthContactEnum> depth_contact;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 001.000.000.000
struct EllipseType {
    /// \brief This element represents the length of the semi-major axis.
    /// xsd type: DistanceType
    double semi_major_axis_length = 0.0;
    /// \brief This element represents the length of the semi-minor axis.
    /// xsd type: DistanceType
    double semi_minor_axis_length = 0.0;
    /// \brief This element represents the orientation as the angle between the semi-major
    /// axis and true north.
    /// xsd type: AngleHalfType
    double orientation = 0.0;
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 001.000.000.000
struct UncertaintyType {
    /// \brief This element represents an ellipse describing the 1-sigma position
    /// uncertainty. The ellipse is defined by the length of its semi-major and
    /// semi-minor axes. The orientation of the ellipse defines the angle between
    /// the semi-major axis and true north.
    EllipseType uncertainty_ellipse = {};
    /// \brief This element represents 1-sigma position uncertainty perpendicular to the
    /// sibling UncertaintyEllipse surface (in the up-down direction). Combined
    /// with the sibling UncertaintyEllipse this results in an uncertainty
    /// ellipsoid with "height".
    /// xsd type: DistanceType
    tl::optional<double> uncertainty_vertical;  // optional
    /// \brief Measured as the angle between the projection of the slant range position
    /// uncertainty axis onto the level plane and the slant range position
    /// uncertainty axis. Positive angle is measured counter-clockwise from local
    /// level.
    /// xsd type: AngleHalfType
    tl::optional<double> uncertainty_tilt;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 001.000.002.001
struct FixedPositionType {
    /// \brief For moving entities, it is highly recommended that the time data be
    /// populated. Generally, services are encouraged to include altitude and/or
    /// time data whenever it is known.
    Point2D_ReportedType fixed_point = {};
    /// \brief Provides an estimate of position uncertainty.
    tl::optional<UncertaintyType> uncertainty;  // optional
    /// \brief The magnitude of the datum position error in meters.
    tl::optional<double> datum_error;  // optional
};

/// \brief This type contains the 1-sigma covariance of line of sight angles and slant
/// range. The covariance is symmetric and therefore the covariance values
/// expressed here are the minimum set.
/// uci_version: 000.000.000.000
struct LOS3D_CovarianceType {
    /// \brief Row 1 Column 1 term of the result matrix. Vertical Vertical angle-angle
    /// covariance. As radian is unitless result is unitless.
    double rv_rv = 0.0;
    /// \brief Row 1 Column 2 term of the result matrix. Vertical Horizontal angle-angle
    /// covariance. As radian is unitless result is unitless.
    double rv_rh = 0.0;
    /// \brief Row 2 Column 2 term of the result matrix. Horizontal Horizontal angle-angle
    /// covariance. As radian is unitless result is unitless.
    double rh_rh = 0.0;
    /// \brief Row 1 Column 3 term of the result matrix. Slant Range Vertical
    /// position-angle covariance. The result is in units of meters.
    tl::optional<double> ps_rv;  // optional
    /// \brief Row 2 Column 3 term of the result matrix. Slant Range Horizontal
    /// position-angle covariance. The result is in units of meters.
    tl::optional<double> ps_rh;  // optional
    /// \brief Row 3 Column 3 term of the result matrix. Slant Range Slant Range
    /// position-position covariance. The result is in units of meters squared.
    tl::optional<double> ps_ps;  // optional
};

/// \brief The ID type that refers to a commandable and/or autonomous Capability of a
/// Subsystem.
/// uci_version: 000.000.000.000
struct CapabilityID_Type {
    std::string uuid = {};  // from ID_Type
    std::string descriptive_label = {};  // from ID_Type  // optional
};

/// \brief This type contains the one-sigma angular rate uncertainty with respect to a
/// 2D coordinate system normal to the LOS. If the 2D coordinate system rotates
/// about the LOS at a given roll rate, care should be taken to account for the
/// rotation of the reference frame.
/// uci_version: 000.000.000.000
struct RelativeAngleRateUncertaintyLOS3D_Type {
    /// \brief Discrete value indicating the one-sigma error in the angle rate
    /// perpendicular to the line-of-sight along the cross-vertical axis.
    /// xsd type: AngleRateType
    double los_cross_vertical_angle_rate_error = 0.0;
    /// \brief Discrete value indicating the one-sigma error in the angle rate
    /// perpendicular to the line-of-sight along the cross-horizontal axis.
    /// xsd type: AngleRateType
    double los_cross_horizontal_angle_rate_error = 0.0;
};

/// \brief This type contains the 1-sigma relative angular uncertainty with respect a
/// 2D coordinate frame normal to the LOS. This uncertainty is expressed with
/// respect to cross-vertical and cross-horizontal axes aligned to the X,Y axes
/// of the unrotated 2D reference frame.
/// uci_version: 001.000.000.000
struct RelativeAngleUncertaintyLOS3D_Type {
    /// \brief Discrete value indicating the one-sigma error along the cross-vertical
    /// axis. Refer to parent RelativeAngleUncertaintyLOS3D_Type for description of
    /// the cross-vertical axis.
    /// xsd type: AnglePositiveType
    double los_cross_vertical_angle_error = 0.0;
    /// \brief Discrete value indicating the one-sigma error along the cross-horizontal
    /// axis. Refer to parent RelativeAngleUncertaintyLOS3D_Type for description of
    /// the cross-horizontal axis.
    /// xsd type: AnglePositiveType
    double los_cross_horizontal_angle_error = 0.0;
};

/// \brief The common base type for all UCI Unit Vectors. All extension types should
/// end in "UnitVectorType".
/// uci_version: 000.000.000.000
struct UnitVectorType {
    /// \brief Indicates the X axis unit vector component.
    /// xsd type: UnitBallFloatType
    float x = 0.0f;
    /// \brief Indicates the Y axis unit vector component.
    /// xsd type: UnitBallFloatType
    float y = 0.0f;
    /// \brief Indicates the Z axis unit vector component.
    /// xsd type: UnitBallFloatType
    float z = 0.0f;
};

/// \brief This Type defines a LOS in terms of a 3D LOS unit vector. The LOS angular
/// rates and associated angle and rate errors are provided in a 2D coordinate
/// system normal to the LOS vector. This coordinate system may be rotated
/// about the LOS unit vector defined by a roll angle. The 3D LOS unit vector's
/// orientation is defined with respect to one of several standard reference
/// frames. Additional details may be found in the element annotations.
/// uci_version: 001.000.000.000
struct RelativeAnglesLOS3D_Type {
    /// \brief Indicates the base reference frame for the LOS_UnitVector data. Four
    /// reference frame options are enumerated: Body, NED, Inertial, and
    /// Capability. The Body frame is defined relative to the host platform, the
    /// NED frame is a local North, East, Down frame, the Inertial frame is similar
    /// to the NED frame with the addition of a Wander Angle, the Capability frame
    /// is defined with respect to the subsystem providing the associated
    /// Capability. Additional details can be found in the annotations for each
    /// enumeration value.
    LOS_ReferenceEnum los_reference_frame = LOS_ReferenceEnum::Unspecified;
    /// \brief This indicates the Capability that defines the reference frame for the LOS
    /// unit vector when the Capability Enumeration is used in the
    /// LOS_ReferenceFrame element.
    tl::optional<CapabilityID_Type> capability_id;  // optional
    /// \brief Line of sight vector from the system to the Entity. The meaning of the
    /// X,Y,Z components of the LOS vector depends upon the enumeration value of
    /// the sibling LOS_ReferenceFrame element.
    UnitVectorType los_unit_vector = {};
    /// \brief Roll angle of the LOS reference frame around the unit vector to the entity.
    /// Positive angle results in a clockwise rotation.
    /// xsd type: AngleType
    tl::optional<double> los_reference_frame_roll;  // optional
    /// \brief The angular uncertainty of the entity with respect to the unit vector. This
    /// uncertainty is expressed in a 2D coordinate frame normal to the LOS Unit
    /// Vector with cross-vertical and cross-horizontal axes. For the special case
    /// where the entity is in the X-Y plane of the reference coordinate frame
    /// defined by sibling element LOS_ReferenceFrame and sibling element
    /// LOS_ReferenceFrameRoll is zero or not provided, the cross-vertical error is
    /// the error along the z-axis (elevation error if NED or inertial frame), and
    /// the cross-horizontal error is the error in the x-y plane (bearing error if
    /// NED or inertial frame). For the general case, the cross-vertical and
    /// cross-horizontal axes are rotated from the X-Y plane of the reference frame
    /// to the plane of the unit vector around the y-axis of the reference frame
    /// (rotation by the elevation angle for the NED and inertial reference frames)
    /// - and then rotated clockwise around the LOS unit vector by sibling field
    /// LOS_ReferenceFrameRoll.
    tl::optional<RelativeAngleUncertaintyLOS3D_Type> relative_angle_uncertainty_los3_d;  // optional
    /// \brief Roll rate of the LOS reference frame around the unit vector to the entity.
    /// Positive angle results in a clockwise roll rate. Refer to sibling
    /// RelativeAngleUncertaintyLOS3D for description of the cross-vertical and
    /// cross-horizontal axes with zero roll rate.
    /// xsd type: AngleRateType
    tl::optional<double> los_reference_frame_roll_rate;  // optional
    /// \brief Indicates the Angle Rate perpendicular to the line-of-sight along the
    /// cross-vertical axis, adjusted by sibling LOS_ReferenceFrameRollRate if
    /// present. Refer to sibling RelativeAngleUncertaintyLOS3D for description of
    /// the cross-vertical axis with zero roll rate.
    /// xsd type: AngleRateType
    tl::optional<double> los_cross_vertical_angle_rate;  // optional
    /// \brief Indicates the Angle Rate perpendicular to the line-of-sight along the
    /// cross-horizontal axis, adjusted by sibling LOS_ReferenceFrameRollRate if
    /// present. Refer to sibling RelativeAngleUncertaintyLOS3D for description of
    /// the cross-horizontal axis with zero roll rate.
    /// xsd type: AngleRateType
    tl::optional<double> los_cross_horizontal_angle_rate;  // optional
    /// \brief The one-sigma uncertainty in the angular rate (sibling elements
    /// LOS_CrossVerticalAngleRate and LOS_CrossHorizontalAngleRate) of the entity
    /// with respect to the 2D coordinate system normal to the 3D LOS unit vector,
    /// adjusted by the roll rate (sibling element LOS_ReferenceFrameRollRate). See
    /// sibling RelativeAngleUncertaintyLOS3D for a detailed description of the
    /// coordinate system.
    tl::optional<RelativeAngleRateUncertaintyLOS3D_Type> relative_angle_rate_uncertainty_los3_d;  // optional
};

/// \brief This type contains kinematic information about a point along a LOS
/// consisting of the Slant Range, Range Rate and associated 1-sigma
/// uncertainties. See annotations of individual fields for further details.
/// uci_version: 001.001.000.000
struct RelativeSlantRangeLOS3D_Type {
    /// \brief Indicates the line-of-sight distance between two points.
    /// xsd type: DistanceType
    double slant_range = 0.0;
    /// \brief Discrete value indicating the error in SlantRange.
    /// xsd type: DistanceType
    tl::optional<double> slant_range_error;  // optional
    /// \brief Indicates the relative velocity along the line-of-sight.
    /// xsd type: SpeedType
    tl::optional<double> slant_range_rate;  // optional
    /// \brief Discrete value indicating the one sigma error in SlantRangeRate.
    /// xsd type: DoubleNonNegativeType
    tl::optional<double> slant_range_rate_error;  // optional
};

/// \brief This type describes the kinematics of a point with respect to a coordinate
/// system defined by a 3D LOS unit vector. The coordinate system consists of
/// the LOS and the 2D plane normal to that LOS. The 2D plane may be rotated
/// (rolled) about the LOS unit vector. The Vertical and Horizontal axis of the
/// 2D plane correspond to the X and Y axes of the unrotated frame. The
/// direction of the LOS unit vector is defined with respect to an enumerated
/// reference frame. See individual elements for further details.
/// uci_version: 001.000.000.000
struct LOS3D_KinematicsType {
    /// \brief Describes LOS, angular rates and associated errors of the entity from the
    /// reference position in terms of a 3D LOS unit vector and a 2D coordinate
    /// frame normal to the LOS vector. The 3D LOS unit vector coordinate frame is
    /// defined with respect to one of several standard reference frames. The
    /// angular rates, angular errors, and angular rate errors are defined with
    /// respect to a 2D LOS coordinate frame, normal to the LOS, with an optional
    /// roll rotation.
    RelativeAnglesLOS3D_Type relative_angles_los3_d = {};
    /// \brief Contains relative slant range line of sight information. See annotations of
    /// individual fields for further details.
    tl::optional<RelativeSlantRangeLOS3D_Type> relative_slant_range_los3_d;  // optional
    /// \brief Indicates the 1-sigma covariance of line of sight angles and slant range.
    /// The covariance is symmetric and therefore the covariance values expressed
    /// here are the minimum set.
    tl::optional<LOS3D_CovarianceType> los3_d_orientation_covariance;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 001.001.000.000
struct ArrivalDataType {
    /// \brief Signal time of arrival(e.g. pulse-edge) of measurement relative to the
    /// measurement time stamp. Units are in nanoseconds.
    /// xsd type: DurationType
    std::string time_of_arrival = {};  // optional
    /// \brief Time difference of arrival for two receiver measurements. For use with
    /// unambiguous associations of TOAs only. Units are in nanoseconds.
    /// xsd type: DurationType
    std::string time_difference_of_arrival = {};  // optional
    /// \brief Frequency of arrival of measurement. Units are in hertz.
    /// xsd type: FrequencyType
    tl::optional<double> frequency_of_arrival;  // optional
    /// \brief Frequency difference of arrival for two receiver measurements. For use with
    /// unambiguous associations of frequencies only.
    /// xsd type: FrequencyOffsetType
    tl::optional<double> frequency_difference_of_arrival;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct ConeAngleRatesType {
    /// \brief The rate of change of the inner product of the target pointing vector with
    /// the sensor Y-axis. In the case of linear arrays, the Y-axis is the same as
    /// the orientation of the linear array. In the case of two-dimensional arrays,
    /// the Y-axis is the "Horizontal" axis, making it coarsely equivalent to the
    /// Azimuth rate with units of per second.
    tl::optional<double> coscone_y_rate;  // optional
    /// \brief The rate of change of the inner product of the target pointing vector with
    /// the sensor Z axis. This term is only used for two-dimensional arrays. The
    /// Z-axis is the "Down" axis of the array, perpendicular to both the X-axis
    /// (boresight) and the Y-axis (horizontal), making it coarsely equivalent to
    /// the Elevation rate with units of per second.
    tl::optional<double> coscone_z_rate;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct ConeAngleType {
    /// \brief The inner product of the target pointing vector with the sensor Y-axis. In
    /// the case of linear arrays, the Y-axis is the same as the orientation of the
    /// linear array. In the case of two-dimensional arrays, the Y-axis is the
    /// "Horizontal" axis, coarsely equivalent to Azimuth. Values of the inner
    /// product are unitless and bounded [-1,1].
    tl::optional<double> coscone_y;  // optional
    /// \brief The inner product of the target pointing vector with the sensor Z axis.
    /// This term is only used for two-dimensional arrays. The Z-axis is the "Down"
    /// axis of the array, perpendicular to both the X-axis (boresight) and the
    /// Y-axis (horizontal), coarsely equivalent to Elevation. Values of the inner
    /// product are unitless and bounded [-1,1].
    tl::optional<double> coscone_z;  // optional
    /// \brief Indicates the rates of the collected Cone Angle Measurements
    tl::optional<ConeAngleRatesType> rates;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct LOS_AzElRatesType {
    /// \brief Azimuth rate of measurement with units of radians per sec.
    /// xsd type: AngleRateType
    tl::optional<double> azimuth_rate;  // optional
    /// \brief Elevation rate of measurement with units of radians per sec.
    /// xsd type: AngleRateType
    tl::optional<double> elevation_rate;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 001.000.000.000
struct LOS_AzElType {
    /// \brief Indicates the azimuth from an observation point to a point of interest.
    /// Azimuth is defined as the angle between two lines in a global horizontal
    /// plane at the observation point. The first line is from the observation
    /// point to true north. The second line is from the observation point to the
    /// point of interest projected onto the global horizontal plane. An azimuth of
    /// zero indicates true north with values increasing clockwise. The terms
    /// azimuth and bearing are often used interchangeably but they are technically
    /// different. Azimuth values are angles between 0 and 2*Pi radians (0 and 360
    /// degrees) relative to north, in this case true north. Bearing values are a
    /// combination of a reference direction (north or south) and an angle between
    /// 0 and Pi radians (0 and 180 degrees) towards the east or west direction.
    /// For example, an azimuth of Pi/2 radians (90 degrees) is equivalent to a
    /// bearing of "North 90 East" or "South 90 East". UCI uses azimuth because it
    /// is easier for machine/software use.
    /// xsd type: AnglePositiveType
    tl::optional<double> azimuth;  // optional
    /// \brief Indicates the elevation from an observation point to a point of interest.
    /// Elevation is defined as the angle between two lines in a global vertical
    /// plane at the observation point. The first line originates from the
    /// observation point and extends along the azimuth. The second line is from
    /// the observation point to the point of interest. An elevation of zero
    /// indicates the point of interest is in the observation point's horizontal
    /// plane. Elevation values are positive when the point of interest is above
    /// the horizontal plane, negative when below.
    /// xsd type: AngleType
    tl::optional<double> elevation;  // optional
    /// \brief Indicates the rates of the collected Azimuth and/or Elevation Measurements
    tl::optional<LOS_AzElRatesType> rates;  // optional
};

