/// uci_version: 000.000.000.000
struct ConeAngleSlantRangeCovarianceRatesType {
    /// \brief The covariance between target slant range rate and the inner product of the
    /// target pointing vector and the Y-axis of the array face. In the case of
    /// linear arrays, the Y-axis is the same as the orientation of the linear
    /// array. In the case of two-dimensional arrays, the Y-axis is the
    /// "Horizontal" axis, coarsely equivalent to Azimuth. This term has units of
    /// meters per second.
    tl::optional<double> coscone_y_slant_range_rate;  // optional
    /// \brief The covariance between target slant range rate and the inner product of the
    /// target pointing vector and the Z-axis of the array face. The Z-axis is the
    /// "Down" axis of the array, perpendicular to both the X-axis (boresight) and
    /// the Y-axis (horizontal), coarsely equivalent to Elevation. This term is
    /// only used for two-dimensional arrays and has units of meters per second.
    tl::optional<double> coscone_z_slant_range_rate;  // optional
    /// \brief The covariance between target slant range and the rate of change of the
    /// inner product of the target pointing vector and the Y-axis of the array
    /// face. In the case of linear arrays, the Y-axis is the same as the
    /// orientation of the linear array. In the case of two-dimensional arrays, the
    /// Y-axis is the "Horizontal" axis, coarsely equivalent to Azimuth. This term
    /// has units of meters per second.
    tl::optional<double> slant_range_coscone_y_rate;  // optional
    /// \brief The covariance between target slant range and the rate of change of the
    /// inner product of the target pointing vector and the Z-axis of the array
    /// face. The Z-axis is the "Down" axis of the array, perpendicular to both the
    /// X-axis (boresight) and the Y-axis (horizontal), coarsely equivalent to
    /// Elevation. This term is only used for two-dimensional arrays and has units
    /// of meters per second.
    tl::optional<double> slant_range_coscone_z_rate;  // optional
};

