    /// \brief Down-East velocity-acceleration covariance with units of meters squared per
    /// second cubed.
    tl::optional<double> vd_ae;  // optional
    /// \brief Down-Down velocity-acceleration covariance with units of meters squared per
    /// second. Required when the acceleration includes a down component.
