/// \brief Used to compare different items (Task, Capability Command, Capability
/// Activity, etc.). This is accomplished by first comparing two
/// ComparableRankingTypes' priority values. In the event of the items having
/// equal priority values the precedence values are then compared. For example,
/// Task A has a (priority, precedence) value pair of (4, 10), Task B has a
/// (priority, precedence) value pair of (4, 23), Task C has a (priority,
/// precedence) value pair of (7, 2): the ranking order would be first Task A,
/// then Task B, then Task C. Since Task A and Task B have the same relative
/// priority value, Task A will be ranked before Task B because Task A has a
/// higher relative precedence value. Task C will be ranked after Tasks A and B
/// because it has a lower relative priority value than Tasks A and B.
/// uci_version: 000.000.000.000
struct ComparableRankingType {
    /// \brief Priority value of an item (Task, Capability Command, Capability Activity,
    /// etc.). Any item with a numerically lower priority value must be considered
    /// prior to any items with a numerically higher priority value. Priority
    /// doesn't necessarily dictate temporal ordering. A value of zero is highest
    /// priority, next highest is one, etc. Priority changes monotonically. For
    /// example, given values A=6, B=4, C=3, the order should be first C, then B,
    /// then A, with C being the highest relative priority.
    uint32_t priority = 0;
    /// \brief Precedence value of an item (Task, Capability Command, Capability Activity,
    /// etc.). Any item with a numerically lower precedence value must be
    /// considered prior to any items with a numerically higher precedence value.
    /// Precedence doesn't necessarily dictate temporal ordering. A value of zero
    /// is highest precedence, next highest is one, etc. Precedence changes
    /// monotonically. For example, given values A=6, B=4, C=3, the order should be
    /// first C, then B, then A, with C being the highest relative precedence.
    uint32_t precedence_within_priority = 0;
};

