/// \brief This type indicates a variety of security information for a data asset
/// including how a data asset shall be stored, protected, and destroyed.
/// uci_version: 000.000.000.000
struct SecurityInformationType {
    /// \brief A single indicator of the highest level of classification applicable to an
    /// information resource or portion within the domain of classified national
    /// security information.
    ClassificationEnum classification = ClassificationEnum::Unspecified;
    /// \brief Identifies the national government or international organization that have
    /// purview over the classification marking of an information resource or
    /// portion therein. Within protected internal organizational spaces this
    /// element may include up to 1000 indicators identifying information which
    /// qualifies as foreign government information for which the source(s) of the
    /// information must be concealed. Measures must be taken prior to
    /// dissemination of the information to conceal the source(s) of the foreign
    /// government information. Specifically, under these specific circumstances,
    /// when data are moved to the shared spaces, the non-disclosable owner(s)
    /// and/or producer(s) listed in this data element's value should be removed
    /// and replaced with "FGI".
    std::vector<OwnerProducerChoiceType> owner_producer = {};
    /// \brief When true, is used to signify that multiple values in the OwnerProducer
    /// element are JOINT owners of the data.
    tl::optional<bool> joint;  // optional
    /// \brief Identifies sensitive compartmented information control system(s).
    std::vector<SCI_ControlsChoiceType> sci_controls = {};
    /// \brief Identifies the defense or intelligence programs for which special access is
    /// required.
    /// xsd type: SAR_IdentifierType (pattern [A-Z_0-9\-]{1,100})
    std::vector<std::string> sar_identifier = {};
    /// \brief Identifies DoE markings.
    std::vector<AtomicEnergyMarkingsChoiceType> atomic_energy_markings = {};
    /// \brief Identifies the expansion or limitation on the distribution of information.
    /// List size for this element is based on "Select All That Apply" condition.
    std::vector<DisseminationControlsEnum> dissemination_controls = {};
    /// \brief Identifies the country/countries and/or international organization(s) to
    /// which classified information may be displayed but NOT released based on the
    /// determination of an originator in accordance with established foreign
    /// disclosure procedures. This element is used in conjunction with the
    /// DisplayOnly Dissemination Controls value.
    std::vector<ReleasableToChoiceType> display_only_to = {};
    /// \brief Identifies information which qualifies as foreign government information
    /// for which the source(s) of the information is not concealed. The attribute
    /// can indicate that the source of information of foreign origin is UNKNOWN.
    std::vector<FGI_SourceOpenChoiceType> fgi_source_open = {};
    /// \brief Identifies the country or countries and/or international organization(s) to
    /// which classified information may be released based on the determination of
    /// an originator in accordance with established foreign disclosure procedures.
    /// This element is used in conjunction with the Dissemination Controls element.
    std::vector<ReleasableToChoiceType> releasable_to = {};
    /// \brief Identifies the expansion or limitation on the distribution of an
    /// information resource or portion within the domain of information
    /// originating from non-intelligence components.
    std::vector<NonIC_MarkingsChoiceType> non_ic_markings = {};
    /// \brief Identifies, by name or personal identifier, and position title of the
    /// original classification authority for a resource.
    /// xsd type: WhitespaceVisibleString1024Type (pattern [\s!-~]{0,1024})
    std::string classified_by = {};  // optional
    /// \brief A description of the reasons that the classification of this element is
    /// more restrictive than a simple roll-up of the sub elements would result in.
    /// This acts as an indicator to rule engines that there is not accidental over
    /// classification going on and to users that special care beyond what the
    /// portion marks reveal must be taken when using this data. Use of this mark
    /// does not replace the need for the compilation reason being defined in the
    /// prose in accordance with ISOO Directive 1. For example this would document
    /// why 3 Unclassified bullet items form a Secret List. Without this reason
    /// being noted the above described document would be considered to be
    /// miss-marked and overclassified.
    /// xsd type: WhitespaceVisibleString1024Type (pattern [\s!-~]{0,1024})
    std::string compilation_reason = {};  // optional
    /// \brief Identifies, by name or personal identifier, of the derivative
    /// classification authority.
    /// xsd type: WhitespaceVisibleString1024Type (pattern [\s!-~]{0,1024})
    std::string derivatively_classified_by = {};  // optional
    /// \brief This element is used primarily at the resource level. One or more reason
    /// indicators or explanatory text describing the basis for an original
    /// classification decision. It is manifested only in the 'Reason' line of a
    /// resource's classification authority block.
    /// xsd type: WhitespaceVisibleString4096Type (pattern [\s!-~]{0,4096})
    std::string classification_reason = {};  // optional
    /// \brief One or more indicators of the expansion or limitation on the distribution
    /// of an information resource or portion within the domain of information
    /// originating from non-US components. List size for this element is based on
    /// "Select All That Apply" condition.
    std::vector<NonUS_ControlsEnum> non_us_controls = {};
    /// \brief A citation of the authoritative source or reference to multiple sources of
    /// the classification markings used in a classified resource. It is manifested
    /// only in the 'Derived From' line of a document's classification authority
    /// block. ISOO's guidance is: Source of derivative classification. (1) The
    /// derivative classifier shall concisely identify the source document or the
    /// classification guide on the "Derived From" line, including the agency and,
    /// where available, the office of origin, and the date of the source or guide.
    /// An example might appear as: Derived From: Memo, "Funding Problems," October
    /// 20, 2008, Office of Administration, Department of Good Works or Derived
    /// From: CG No. 1, Department of Good Works, dated October 20, 2008 (i) When a
    /// document is classified derivatively on the basis of more than one source
    /// document or classification guide, the "Derived From" line shall appear as:
    /// Derived From: Multiple Sources (ii) The derivative classifier shall include
    /// a listing of the source materials on, or attached to, each derivatively
    /// classified document.
    /// xsd type: WhitespaceVisibleString1024Type (pattern [\s!-~]{0,1024})
    std::string derived_from = {};  // optional
    /// \brief A specific year, month, and day upon which the information shall be
    /// automatically declassified if not properly exempted from automatic
    /// declassification.
    /// xsd type: xs:dateTime (carried as string on the OMS wire)
    std::string declass_date = {};  // optional
    /// \brief A description of an event upon which the information shall be automatically
    /// declassified if not properly exempted from automatic declassification.
    /// xsd type: WhitespaceVisibleString1024Type (pattern [\s!-~]{0,1024})
    std::string declass_event = {};  // optional
    /// \brief A single indicator describing an exemption to the nominal 25-year point for
    /// automatic declassification. This element is used in conjunction with the
    /// Declassification Date or Declassification Event. ISOO has stated it should
    /// be a SINGLE value giving the longest protection. List size for this element
    /// is based on "Select All That Apply" condition.
    std::vector<DeclassExceptionEnum> declass_exception = {};
};

