    /// allocation to any one of the Capabilities is the minimum expectation, 2)
    /// decomposition of the Task into multiple child Tasks allocated across the
    /// multiple required Capabilities is acceptable, 3) there is no expectation
    /// that each Capability must perform the Task.
    std::vector<CapabilityID_Type> capability_id = {};
    /// \brief ID of the performance metric. Valid IDs can be found in the service
    /// contract.
    ForeignKeyType metric_identifier = {};
    /// \brief How the received performance feedback should be interpolated using the
    /// sibling NormalizationElements.
    NormalizationInterpolationEnum interpolation_enum = NormalizationInterpolationEnum::Unspecified;
    /// \brief Actual performance values with their corresponding normalized value using
