/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct MA_ShotDoctrineParametersType {
    /// \brief Use Launch range at which the weapon will intercept the target with high
    /// energy, assuming no platform guidance or weapon guidance errors for:
    /// 1.Current steering 2.Current shooter kinematic conditions (e.g.,
    /// altitude/airspeed) 3.Target turn-and-run maneuver RangeTurnAndRun is not
    /// applicable to ballistic trajectory targets.
    tl::optional<bool> use_range_turn_and_run;  // optional
    /// \brief The magnitude of the maximum angle the target can turn away from the
    /// platform which results in weapon intercept of the target with nominal
    /// energy, assuming an immediate employment command. This field is valid only
    /// if RangeMaxGuidance >= TargetRange >= RangeTurnandRun. This field is never
    /// greater than the magnitude of the target aspect angle. For air platforms,
    /// this turn is in the horizontal plane defined by the north and east axes.
    /// xsd type: AngleHalfPositiveType
    tl::optional<double> digital_maneuvering_cue_angle;  // optional
    /// \brief This field describes the number of shots to be allocated per target.
    tl::optional<int32_t> missiles_per_contact;  // optional
    /// \brief The minimum distance between a platform and a track that a shot will be
    /// released at. Works together with ShootNET to form a shot window
    /// xsd type: DistanceType
    tl::optional<double> shoot_nlt;  // optional
    /// \brief The maximum distance between a platform and a track that a shot will be
    /// released at. Works together with ShootNLT to form a shot window
    /// xsd type: DistanceType
    tl::optional<double> shoot_net;  // optional
    /// \brief This field specifies that MA should recalculate optimal targets during the
    /// engagement
    tl::optional<bool> enable_target_recalculation;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct RequirementDependencyBaseType {
    /// \brief Indicates how the dependent item temporally relates to the sibling
    /// ReferenceRequirement. The temporal relationship can further specified by
    /// sibling elements.
    RequirementDependencyEnum dependency_type = RequirementDependencyEnum::Unspecified;
    /// \brief Indicates the extent to which the item is dependent on the
    /// ReferenceRequirement. See enumerate annotations. A SOFT dependency means
    /// the dependent item can/should finish or start even if some or all sibling
    /// dependency elements can't be satisfied. A HARD dependency means the
    /// dependent item should only finish or start if all the sibling dependent
    /// elements can be satisfied. For example, a dependent item can/should start
    /// even if it has a SOFT finish-to-start dependency on a ReferenceRequirement
    /// that can't be planned/started. This element was adapted from the former
    /// "TaskRequired" element in the Task message.
    OpConstraintTypeEnum dependency_extent = OpConstraintTypeEnum::Unspecified;
    /// \brief Indicates the earliest time, relative to the finish or start of the
    /// ReferenceRequirement, to finish or start the dependent item. If omitted,
    /// the dependent item's earliest finish or start should match the finish or
    /// start of the ReferenceRequirement. For example, if the sibling
    /// DependencyType element indicates FINISH_TO_START then the earliest start
    /// time for the dependent item is the finish time of the ReferenceRequirement
    /// plus the time duration given by this element. Note that the duration given
    /// by this element could be negative; in the example above the dependent
    /// item's earliest start would be prior to the planned/predicted completion of
    /// the ReferenceRequirement by the duration given by this element.
    /// xsd type: DurationType
    std::string earliest_time = {};  // optional
    /// \brief Indicates the latest time, relative to the finish or start of the
    /// ReferenceRequirement, to finish or start the dependent item. If omitted,
    /// the dependent item's latest finish or start should match the finish or
    /// start of the ReferenceRequirement. For example, if the sibling
    /// DependencyType element indicates FINISH_TO_START then the latest start time
    /// for the dependent item is the finish time of the ReferenceRequirement plus
    /// the time duration given by this element. Note that the duration given by
    /// this element could be negative; in the example above the dependent item's
    /// latest start would be prior to the planned/predicted completion of the
    /// ReferenceRequirement by the duration given by this element.
    /// xsd type: DurationType
    std::string latest_time = {};  // optional
};

