/// \brief Defines a line of sight ray in a world inertial frame of reference.
/// uci_version: 001.000.000.000
struct LOS_InertialB_Type {
    /// \brief Indicates the azimuth from an observation point to a point of interest.
    /// Azimuth is defined as the angle between two lines in a global horizontal
    /// plane at the observation point. The first line is from the observation
    /// point to true north. The second line is from the observation point to the
    /// point of interest projected onto the global horizontal plane. An azimuth of
    /// zero indicates true north with values increasing clockwise. The terms
    /// azimuth and bearing are often used interchangeably but they are technically
    /// different. Azimuth values are angles between 0 and 2*Pi radians (0 and 360
    /// degrees) relative to north, in this case true north. Bearing values are a
    /// combination of a reference direction (north or south) and an angle between
    /// 0 and Pi radians (0 and 180 degrees) towards the east or west direction.
    /// For example, an azimuth of Pi/2 radians (90 degrees) is equivalent to a
    /// bearing of "North 90 East" or "South 90 East". UCI uses azimuth because it
    /// is easier for machine/software use.
    /// xsd type: AnglePositiveType
    double azimuth = 0.0;
    /// \brief Indicates the elevation from an observation point to a point of interest.
    /// Elevation is defined as the angle between two lines in a global vertical
    /// plane at the observation point. The first line originates from the
    /// observation point and extends along the azimuth. The second line is from
    /// the observation point to the point of interest. An elevation of zero
    /// indicates the point of interest is in the observation point's horizontal
    /// plane. Elevation values are positive when the point of interest is above
    /// the horizontal plane, negative when below.
    /// xsd type: AngleType
    double elevation = 0.0;
    /// \brief Indicates the line-of-sight distance between the observation point and
    /// point of interest.
    /// xsd type: DistanceType
    tl::optional<double> slant_range;  // optional
};

/// \brief Provides a choice of event offset types.
