/// \brief Describes a position in Radial-Transverse-Normal (RTN) sigmas.
/// uci_version: 001.000.000.000
struct RTN_PositionSigmaType {
    /// \brief Indicates the radial sigma.
    /// xsd type: DistanceType
    double radial_sigma = 0.0;
    /// \brief Indicates the transverse sigma.
    /// xsd type: DistanceType
    double transverse_sigma = 0.0;
    /// \brief Indicates the normal sigma.
    /// xsd type: DistanceType
    double normal_sigma = 0.0;
};

/// \brief Describes a velocity in Radial-Transverse-Normal (RTN) sigmas.
/// uci_version: 000.000.000.000
struct RTN_VelocitySigmaType {
    /// \brief Indicates the radial sigma.
    /// xsd type: SpeedType
    double radial_sigma = 0.0;
    /// \brief Indicates the transverse sigma.
    /// xsd type: SpeedType
    double transverse_sigma = 0.0;
    /// \brief Indicates the normal sigma.
    /// xsd type: SpeedType
    double normal_sigma = 0.0;
};

/// \brief The covariance data provides a measure of the strength of the correlation
/// between two or more elements of the orbit or tracked object state
/// (position/velocity/other quantities), each of which have some underlying
/// degree of statistical variation. The correlation coefficient between any
/// two elements of the state can be derived from the variances and covariances
/// of the two elements.
/// uci_version: 001.001.000.000
struct VCM_DataType {
    /// \brief Sigma estimates for the satellite position.
    tl::optional<RTN_PositionSigmaType> position_sigma;  // optional
    /// \brief Sigma estimates for the satellite velocity.
    tl::optional<RTN_VelocitySigmaType> velocity_sigma;  // optional
    /// \brief Weighted Root Mean Square of last differential correction on the satellite.
    tl::optional<double> weighted_rms;  // optional
    /// \brief The covariance matrix along with its associated category that defines the
    /// elements represented in the covariance matrix. See the individual category
    /// enumerations for detailed explanations.
    CovarianceMatrixType covariance_matrix = {};
};

/// \brief Indicates the vector and covariance data of the VCM.
/// uci_version: 002.000.000.000
struct OrbitalVCM_Type {
    /// \brief Indicates kinematics vector in the Earth-Centered Inertial (ECI) J2000
    /// (ECI-J2K) Reference System.
    OrbitalKinematicsStandardFrameChoiceType state_vector = {};
    /// \brief The covariance data provides a measure of the strength of the correlation
    /// between two or more elements of the orbit or tracked object state
    /// (position/velocity/other quantities), each of which have some underlying
    /// degree of statistical variation. The correlation coefficient between any
    /// two elements of the state can be derived from the variances and covariances
    /// of the two elements.
    VCM_DataType covariance_data = {};
    /// \brief Represents the revolution number (Revs) at the Epoch.
    tl::optional<uint32_t> revolution_number;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 001.000.000.000
struct COE_EquatorialOrientationType {
    /// \brief Indicates the angle measured from the principal direction to perigee in the
    /// direction of the spacecraft's motion. Used for equatorial orbits with no
    /// Ascending Node. Required when Eccentricity is non-zero. Units in radians.
    /// Valid values range from zero to 2*PI().
    /// xsd type: AnglePositiveType
    tl::optional<double> longitude_of_perigee;  // optional
};

/// \brief Elements to describe orbits that go from south to north.
/// uci_version: 001.000.000.000
struct COE_NonEquatorialOrientationType {
    /// \brief Right ascension of the ascending node (RAAN). Units in radians. Valid
    /// values range from zero to 2*PI(). This element describes the orbital
    /// plane's orientation with respect to the principal direction (vernal equinox
    /// direction); how the orbital plane is rotated in space. RAAN is measured
    /// from the principal direction eastward along the equator to the ascending
    /// node. Thus, the right ascension of the ascending node is the angle from the
    /// principal direction to the ascending node. The ascending node is the point
    /// of intersection of the orbit with the equatorial plane, crossing from the
    /// southern hemisphere to the northern hemisphere.
    /// xsd type: AnglePositiveType
    double right_ascension_of_ascending_node = 0.0;
    /// \brief Argument of perigee is the angle from the body's ascending node to its
    /// periapsis, measured in the direction of motion. Perigee indicates this is
    /// an Earth-centered orbit. Generically, this is the Argument of Periapsis.
    /// Units in radians. Valid values range from zero to 2*PI().
    /// xsd type: AnglePositiveType
    double argument_of_perigee = 0.0;
};

/// \brief Indicates the orientation of the orbital plane in space and of the orbit
/// within its plane.
/// uci_version: 001.001.000.001
struct COE_OrientationType {
    // oneof choice
    /// \brief Indicates that the orbit is non-equatorial. A non-equatorial orbit is an
    /// orbit with a non-zero inclination.
    tl::optional<COE_NonEquatorialOrientationType> non_equatorial_orbit;
    /// \brief Indicates the angle measured from the principal direction to perigee in the
    /// direction of the spacecraft's motion. Used for equatorial orbit where RAAN
    /// and argument of perigee are undefined. Units in radians. Valid values range
    /// from zero to 2*PI.
    tl::optional<COE_EquatorialOrientationType> equatorial_orbit;
};

/// \brief Indicates the set of classic orbital elements (COE) describing an orbit.
/// Elements describing the position of a satellite on the orbit are often
/// considered part of COE but are omitted from this type which is only
/// intended to describe the orbit.
/// uci_version: 002.001.001.000
struct COE_OrbitBaseType {
    /// \brief Indicates the orbit's shape expressed as eccentricity. Eccentricity is a
    /// quantity describing the shape of the satellite's orbit. In mathematics the
    /// eccentricity of a conic section is a measure of how much the shape deviates
    /// from being circular. A value of zero represents a perfect circle. As the
    /// eccentricity varies from zero to 1 the ellipse becomes more "stretched". An
    /// eccentricity of 1 is a parabolic rather than elliptical, and values greater
    /// than 1 are hyperbolas.
    /// xsd type: DoubleNonNegativeType
    double eccentricity = 0.0;
    /// \brief Indicates the tilt of the orbit with respect to the equatorial plane. Units
    /// in radians. Valid values range from zero to PI.
    /// xsd type: AngleHalfPositiveType
    double inclination = 0.0;
    /// \brief Indicates the orientation of the orbital plane in space and of the orbit
    /// within its plane. Equatorial orbits are a special case that result in some
    /// classical orbital elements (COE) for orientation being undefined;
    /// equatorial orbits use alternate elements to define orientation.
    COE_OrientationType orientation = {};
};

/// \brief Indicates the set of classic orbital elements (COE) describing a
/// spacecraft's position in an orbit. Elements describing the size, shape and
/// other characteristics of the orbit are in other types.
/// uci_version: 001.000.000.000
struct COE_PositionType {
    // oneof choice
    /// \brief Indicates position of the spacecraft expressed as the angular distance from
    /// the pericenter which a fictitious body would have if it moved in a circular
    /// orbit, with constant speed, in the same orbital period as the actual body
    /// in its elliptical orbit. This means of expressing position is used for
    /// non-circular orbits. Units in radians. Valid values range from zero to
    /// 2*PI().
    /// xsd type: AnglePositiveType
    tl::optional<double> mean_anomaly;
    /// \brief Indicates the position of the spacecraft expressed as the angle along the
    /// orbital path from the ascending node to the spacecraft's position in the
    /// direction of the spacecraft's motion. This means of expressing position is
    /// used for circular orbits where mean anomaly is undefined. Units in radians.
    /// Valid values range from zero to 2*PI().
    /// xsd type: AnglePositiveType
    tl::optional<double> argument_of_latitude;
    /// \brief Indicates the position expressed as the angle from the principal direction
    /// (vernal equinox direction) to the spacecraft's position vector in the
    /// direction of the spacecraft's motion. This means of expressing position is
    /// used for circular equatorial orbits where mean anomaly and argument of
    /// perigee are undefined. Units in radians. Valid values range from zero to
    /// 2*PI().
    /// xsd type: AnglePositiveType
    tl::optional<double> true_longitude;
};

/// \brief Indicates the default or "catalog" orbital element set (also known as two
/// line element or TLE) for the satellite.
/// uci_version: 002.001.001.000
struct TLE_BaseType {
    double eccentricity = 0.0;  // from COE_OrbitBaseType
    double inclination = 0.0;  // from COE_OrbitBaseType
    COE_OrientationType orientation = {};  // from COE_OrbitBaseType
    /// \brief Time at which the orbital elements are valid. Formatted as UTC DateTime
    /// values.
    /// xsd type: DateTimeType (pattern .+Z)
    std::string epoch = {};
    /// \brief The element set number is a carryover from the legacy Two Line Element set
    /// (TLE) format, and is provided to support processes that transform to/from
    /// that format. Element Set Number increments with each newly generated
    /// element set. A common range is [0,999].
    tl::optional<uint32_t> element_set_number;  // optional
    /// \brief First time derivative of the mean motion, in units of revolutions per day.
    /// This field is only used with the SGP orbital model (ephemeris type = 1).
    tl::optional<double> first_time_derivative_of_mean_motion;  // optional
    /// \brief Second time derivative of the mean motion, in units of revolutions per day.
    /// This field is only used with the SGP orbital model (ephemeris type = 1).
    tl::optional<double> second_time_derivative_of_mean_motion;  // optional
    /// \brief Ballistic drag coefficient.
    tl::optional<double> bstar_drag;  // optional
    /// \brief Position of the spacecraft at the time indicated by the sibling Epoch
    /// element.
    COE_PositionType position = {};
    /// \brief The number of revolutions per day.
    double mean_motion = 0.0;
    /// \brief Represents the revolution number (Revs) at the Epoch.
    tl::optional<uint32_t> revolution_number;  // optional
};

/// \brief The measured orbit determined by spacecraft ranging.
/// uci_version: 002.001.001.000
struct OrbitKinematicsType {
    /// \brief Indicates the default or "catalog" orbital element set (also known as two
    /// line element or TLE) for the satellite.
    tl::optional<TLE_BaseType> element_set;  // optional
    /// \brief Describes satellite orbit at date and time intervals.
    tl::optional<OrbitalEphemerisChoiceType> ephemeris;  // optional
    /// \brief Describes the orbit in terms of a state vector along with covariance data.
    tl::optional<OrbitalVCM_Type> vcm;  // optional
    /// \brief Provides single vector information of the spacecraft's new orbit in
    /// standard coordinate reference frame.
    tl::optional<OrbitalKinematicsChoiceType> single_vector;  // optional
};

/// \brief Indicates a reference asset and associated kinematics.
/// uci_version: 003.000.001.000
struct ReferenceAssetKinematicsType {
    /// \brief Indicates the identity of the object that is to be used as the basis for
    /// the Event.
    AssetType reference_asset = {};
    /// \brief Indicates the kinematics source to use for the sibling Object.
    tl::optional<OrbitalKinematicsSourceEnum> orbit_kinematics_source;  // optional
    /// \brief Use this type when the cataloged orbit is different than the orbit you
    /// have. Use this for lost items, items that have maneuvered, and items that
    /// have changed orbital states between the last cataloging and the current
    /// orbital state. If the expected or last reported orbit is valid, omit this
    /// value.
    tl::optional<OrbitKinematicsType> orbit_kinematics_override;  // optional
};

/// \brief Defines a line of sight ray in a world inertial frame of reference.
/// uci_version: 001.000.000.000
struct LOS_InertialA_Type {
    /// \brief Indicates the azimuth from an observation point to a point of interest.
    /// Azimuth is defined as the angle between two lines in a global horizontal
    /// plane at the observation point. The first line is from the observation
    /// point to true north. The second line is from the observation point to the
    /// point of interest projected onto the global horizontal plane. An azimuth of
    /// zero indicates true north with values increasing clockwise. The terms
    /// azimuth and bearing are often used interchangeably but they are technically
    /// different. Azimuth values are angles between 0 and 2*Pi radians (0 and 360
    /// degrees) relative to north, in this case true north. Bearing values are a
    /// combination of a reference direction (north or south) and an angle between
    /// 0 and Pi radians (0 and 180 degrees) towards the east or west direction.
    /// For example, an azimuth of Pi/2 radians (90 degrees) is equivalent to a
    /// bearing of "North 90 East" or "South 90 East". UCI uses azimuth because it
    /// is easier for machine/software use.
    /// xsd type: AnglePositiveType
    tl::optional<double> azimuth;  // optional
    /// \brief Indicates the elevation from an observation point to a point of interest.
    /// Elevation is defined as the angle between two lines in a global vertical
    /// plane at the observation point. The first line originates from the
    /// observation point and extends along the azimuth. The second line is from
    /// the observation point to the point of interest. An elevation of zero
    /// indicates the point of interest is in the observation point's horizontal
    /// plane. Elevation values are positive when the point of interest is above
    /// the horizontal plane, negative when below.
    /// xsd type: AngleType
    tl::optional<double> elevation;  // optional
    /// \brief Indicates the line-of-sight distance between the observation point and
    /// point of interest.
    /// xsd type: DistanceType
    tl::optional<double> slant_range;  // optional
};

/// \brief This type describes the line of sight (LOS) between two points.
/// uci_version: 001.000.000.000
struct LOS_Type {
    /// \brief Indicates the line-of-sight distance between two points.
    /// xsd type: DistanceType
    tl::optional<double> slant_range;  // optional
    /// \brief Indicates the angle from true north to target point measured from a
    /// reference point to a second point.
    /// xsd type: AnglePositiveType
    tl::optional<double> bearing;  // optional
    /// \brief Indicates the angle between a level plane in the global frame and the line
    /// between the two points. Angles above the plane are positive.
    /// xsd type: AngleType
    tl::optional<double> elevation;  // optional
};

