struct RepetitionFiniteType {
    /// \brief Indicates the number of times the Requirement should be repeated before
    /// being considered complete. This element can be used, for example, to
    /// perform just a single scan of an area or to limit the number of attempts to
    /// acquire a cue.
    uint32_t repetition_attempts = 0;
    /// \brief Indicates the duration between repetitions of the Requirement. If omitted
    /// the interval is left to the discretion of the recipient within other
    /// overall temporal constraints.
    /// xsd type: DurationType
    std::string repetition_interval = {};  // optional
};

/// \brief Indicates a periodic repetition with a specified interval.
/// uci_version: 000.000.000.000
struct RepetitionPeriodicType {
    /// \brief Indicates the duration between repetitions of the Requirement.
    /// xsd type: DurationType
    std::string repetition_interval = {};
};

/// \brief Represents a Time-Based repetition.
/// uci_version: 000.000.000.000
struct RepetitionTimeBasedType {
    // oneof choice
    /// \brief Indicates the Requirement should be done continuously, within other
    /// temporal constraints of the Requirement. This element is oriented towards
    /// Capabilities that are continuous in nature and interruptible. This element
    /// generally shouldn't be used for Capabilities that are discrete and/or
    /// single shot in nature with a physics- and/or design-driven duration.
    tl::optional<RepetitionContinuousType> continuous;
    /// \brief Indicates the Requirement should be repeated a specific number of times
    /// within the overall temporal constraints of the Requirement. This element is
    /// oriented towards capabilities that are discrete and/or single shot in
    /// nature.
    tl::optional<RepetitionFiniteType> finite;
    /// \brief Indicates the Requirement should be repeated periodically within the
    /// overall temporal constraints of the Requirement. Depending on perspective
    /// and/or Capability type, this element indicates the time duration between
    /// starts of successive repetitions of the Requirement, time between revisits
    /// to a target or area in a search volume or other meanings. A periodic
    /// command with no end time continues until canceled. This element is oriented
    /// towards Capabilities that are discrete and/or single shot in nature.
    tl::optional<RepetitionPeriodicType> periodic;
};

/// \brief Provides a choice between Time-Based and Event-Based Repetition.
/// uci_version: 003.000.001.000
struct RepetitionType {
    // oneof choice
    /// \brief Indicates when the Requirement should be repeated on a Time basis.
    tl::optional<RepetitionTimeBasedType> time_based;
    /// \brief Since it may be difficult to predict the exact time of an event, this
    /// element allows for the same input to be used in planning as the cycle moves
    /// from week-ahead planning to day-ahead planning.
    tl::optional<RepetitionEventBasedType> event_based;
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct TimeWindowType {
    /// \brief Indicates the begin and end times for the time window.
    tl::optional<DateTimeRangeType> range;  // optional
    /// \brief Indicates the duration or active/execution time for the time window.
    /// xsd type: DurationType
    std::string duration = {};  // optional
};

/// \brief Indicates the Time Window and the Repetition which can be Time-Based or
/// Event-Based.
/// uci_version: 003.000.001.000
struct RepetitionConstraintsType {
    /// \brief Indicates the nature of the repetitions.
    RepetitionType repetition = {};
    /// \brief The time window for which the sibling Repetition applies.
    tl::optional<TimeWindowType> time_window;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct WeekdayIntervalType {
    /// \brief Indicates the period of time during which the weekday interval is valid. In
    /// other words, this sets the number of weeks/months during which the
    /// WeekdayInterval is active.
    DateTimeRangeType time_span = {};
    /// \brief Indicates the days of the week in which the interval is valid. List size
    /// for this element is based on "Select All That Apply" condition.
    std::vector<WeekdayEnum> weekday = {};
    /// \brief Indicates the number of weeks between occurrences. 1 = weekly, 2 = every
    /// other week, etc.
    uint32_t weekly_interval_period = 0;
    /// \brief Indicates the time of day, on a day given by the Weekday element, at which
    /// the interval starts.
    /// xsd type: TimeType (pattern .+Z)
    std::string start_time = {};  // optional
    /// \brief Indicates the duration of each occurrence.
    /// xsd type: DurationType
    std::string duration = {};  // optional
};

/// \brief Provides a choice of timing constraints including repetitive timing and
/// event based repetition.
/// uci_version: 003.000.001.000
struct TimingConstraintsType {
    // oneof choice
    /// \brief Indicates that the timing should be As Soon As Possible.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> as_soon_as_possible;
    /// \brief Indicates the time window during which the Requirement should be initiated
    /// and, once initiated, the duration.
    tl::optional<TimeWindowType> time_window;
    /// \brief Indicates a recurring time. For example, a recurring time as a constraint
    /// on a Task may result in the need for a Task or other Requirement to be
    /// broken down into multiple discrete children corresponding to each interval.
    tl::optional<WeekdayIntervalType> weekday_interval;
    /// \brief Indicates a repetition and defines the number and frequency of product
    /// collection and generation such as start/stop/frequency or min # of
    /// collections.
    tl::optional<RepetitionConstraintsType> repetitive;
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 003.000.001.000
struct RequirementTimingType {
    /// \brief Indicates the type of timing constraint or status.
    RequirementTimingEnum timing_type = RequirementTimingEnum::Unspecified;
    /// \brief Indicates timing, of the type indicated by the sibling TimingType element,
    /// for the Requirement.
    std::vector<TimingConstraintsType> timing = {};
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct MA_RequirementConstraintsType {
    /// \brief Indicates a constraint in the form of the Rank of the associated
    /// Requirement (Effect, Action, Task, [Capability]Command or Response).
    tl::optional<ComparableRankingType> rank;  // optional
    /// \brief Indicates whether a) an in-work/planned item or items of a lower rank
    /// should be interrupted/replanned in order to address this item (TRUE) or b)
    /// this item should be simply queued/planned according to rank without
    /// interrupting in-work/planned items (FALSE). For example, a Task being added
    /// to an existing TaskPlan (TaskPlanCommand constrained by an existing
    /// TaskPlan) would potentially cause unlocked Tasks of lower rank in the
    /// existing TaskPlan to be unallocated if 1) this element indicated TRUE and
    /// 2) the lower ranked Tasks prevented the higher ranked Task from being
    /// allocated.
    tl::optional<bool> interrupt_lower_rank;  // optional
    /// \brief Indicates allocation related constraints which can vary by Requirement at
    /// the discretion of the creator.
    tl::optional<MA_RequirementAllocationParametersType> allocation;  // optional
    /// \brief Indicates a temporal constraint on the Requirement. Allows for defining for
    /// each timing type (RequirementTimingEnum).
    std::vector<RequirementTimingType> timing = {};
    /// \brief Indicates a constraint in the form of kinematic position of Requirement
    /// actor or actors. When more than one is given they are logically ANDed.
    std::vector<MA_RequirementKinematicConstraintsType> kinematic = {};
    /// \brief Indicates a constraint in the form of a temporal dependency between
    /// Requirements; between Effect, Action, Task, [Capability]Command or Commands
    /// or Response. If more than one is given, they are logically ANDed. For
    /// example, a pre-strike image collection (PO Task) might be required several
    /// minutes prior to a strike (Strike Task) to determine combat ID and target
    /// coordinates. A post-strike image collection (PO Task) might be required
    /// several minutes after the strike to inform battle damage assessment. The
    /// dependency between the three Tasks can be established with this element.
    /// Assuming the Strike Task is the most difficult to plan/coordinate, the
    /// other two Tasks would likely each have dependencies on the Strike Task in
    /// order to orchestrate the desired "look-shoot-look" sequence.
    std::vector<RequirementDependencyType> dependency = {};
    /// \brief Indicates the maximum allowed classification level of the networks that the
    /// allocated system can disseminate products to for this task. The allocated
    /// system must have a dissemination route for data at this classification or
    /// lower. For example, when trying to collect data to hand-off to an
    /// unclassified system or network, the allocated system has to be able to
    /// generate products at no higher than the specified level and have the
    /// authority to disseminate on a network at no higher than the specified
    /// classification level.
    tl::optional<DataProductClassificationLevelType> max_product_dissemination_classification_level;  // optional
    /// \brief Indicates a constraint in the form of an analytic measure that the
    /// Requirement must satisfy when planned/executed.
    tl::optional<MA_AnalyticConstraintsType> analytic;  // optional
    /// \brief Indicates a constraint on the highest acceptable classification level at
    /// which the Response can be planned and executed.
    tl::optional<SecurityInformationType> acceptable_classification_level;  // optional
    /// \brief Indicates whether or not communications are required when executing the
    /// Requirement. In this context, "required" means the creator or a Requirement
    /// considers communications as necessary for C2 and/or Product dissemination
    /// related to this Requirement, independent of the type of vehicle that it is
    /// allocated to. This element may result in consideration of communications
    /// allocations during Requirement allocation.
    tl::optional<bool> comms_required;  // optional
    /// \brief Indicates other types of Requirements that can be decomposed from, used to
    /// plan, used to implement, inherited from traced parents or otherwise
    /// associated with the subject Requirement.
    tl::optional<MA_RequirementTaxonomyType> allowed_requirement_types;  // optional
    /// \brief Indicates other types of Requirements that cannot be decomposed from, used
    /// to plan, used to implement, inherited from traced parents or otherwise be
    /// associated with the subject Requirement.
    tl::optional<MA_RequirementTaxonomyType> excluded_requirement_types;  // optional
    /// \brief Free-text explanation of sibling constraints, additional extraordinary
    /// constraints, etc.
    /// xsd type: VisibleString1024Type (pattern [ -~]{0,1024})
    std::string constraints_narrative = {};  // optional
    /// \brief Indicates an allowed domain/environment which the Requirement can be
    /// employed from and and allowed "target" domain/environment. See enumerated
    /// type annotations for further details. List size for this element is based
    /// on "Select All That Apply" condition.
    std::vector<EnvironmentPairingEnum> allowed_domain_pairing = {};
    /// \brief Indicates an excluded domain/environment which the Requirement can't be
    /// employed from an excluded "target" domain/environment. See enumerated type
    /// annotations for further details. List size for this element is based on
    /// "Select All That Apply" condition.
    std::vector<EnvironmentPairingEnum> excluded_domain_pairing = {};
    /// \brief Provides shot doctrine parameters that this requirement should adhere to.
    tl::optional<MA_ShotDoctrineParametersType> shot_doctrine_parameters;  // optional
};

