/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct RequirementGuidanceType {
    /// \brief Indicates an intended form of Mission C2 for the Requirement. In a System
    /// with multiple forms of Mission C2 and multiple operators, this element can
    /// be used to control which services, operators, etc. consider the Requirement
    /// as an input. List size for this element is based on "Select All That Apply"
    /// condition.
    std::vector<RequirementUsageEnum> usage = {};
    /// \brief Indicates resource allocation, timeliness and approval guidance constraints
    /// on the planning and execution of the Requirement by tactical nodes/Systems.
    /// This guidance is generally given by operational C2 nodes to tactical C2
    /// nodes per Requirement (per "tasking"). See enumerate annotations for
    /// further details. The enumerates reflect well-established, short-hand
    /// terminology. The guidance and enumerates functionally overlap with some UCI
    /// concepts such as Approval Policy but should be thought of as informing the
    /// creation of or tactical use of those other UCI concepts; the enumerates
    /// give up front guidance, prior to creation of Approval Policies, resource
    /// scheduling, timing constraints, etc. This element can result in approval
    /// being required, in addition to what is required by the ApprovalPolicy of
    /// the System, but it cannot disable an approval required by an applicable
    /// ApprovalPolicy.
    tl::optional<TacticalPlanningAndExecutionEnum> tactical_planning_and_execution;  // optional
    /// \brief Indicates guidance on how to react to a failure to complete the
    /// Requirement. For example, if a Strike Task failed and this element
    /// indicated RETRY then a tactical node would be expected to re-strike the
    /// target subject to other constraints. See enumeration annotations for
    /// further details.
    tl::optional<FailureGuidanceEnum> failure;  // optional
};

