/// \brief Tasking sources work at different levels of detail and abstraction,
/// progressing from what to do to how specifically to do it. Inputs from
/// abstract tasking sources and Tasks can be decomposed into discrete,
/// actionable Tasks. This type provides traceability to the external tasking
/// or Task from which this Task was derived.
/// uci_version: 002.000.000.000
struct TraceabilityType {
    /// \brief Indicates a Requirement (Effect, Action, Task, [Capability]Command or
    /// Response) which the subject traces/originates from.
    std::vector<RequirementInstanceID_ChoiceType> requirement = {};
    /// \brief Indicates a reference to an external (non-UCI) tasking source, the
    /// collection deck, which the subject traces/originates from.
    std::vector<CollectionDeckTraceabilityType> collection_deck_traceability = {};
    /// \brief Indicates a reference to an external (non-UCI) tasking source, Airborne
    /// Collection Tasking Message, the subject traces/originates from.
    std::vector<ACTDF_TraceabilityType> actdf_traceability = {};
    /// \brief Indicates a reference to an external (non-UCI) tasking source, Essential
    /// Element of Information, the subject traces/originates from.
    std::vector<EEI_ID_Type> eei_id = {};
    /// \brief Indicates a reference to an external (non-UCI) tasking source, the Air
    /// Tasking Order, the subject traces/originates from.
    std::vector<ATO_TraceabilityType> ato_traceability = {};
    /// \brief Indicates a reference to an external (non-UCI) tasking source, Airborne
    /// Overhead Cooperative Operations, the subject traces/originates from.
    tl::optional<AOCO_TraceabilityType> aoco_traceability;  // optional
    /// \brief Indicates a reference to an external (non-UCI) tasking source: Space
    /// Tasking Order.
    tl::optional<CS_STO_TraceabilityType> sto_traceability;  // optional
};

