/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 003.000.003.000
struct EntityCharacteristicType {
    // oneof choice
    /// \brief Indicates the identity to be compared to the identity in the Entity message.
    tl::optional<IdentityComparisonType> identity;
    /// \brief Indicates the identity staleness to be compared to the identity staleness
    /// in the Entity message. This choice requires a corresponding Identity
    /// TargetClause.
    /// xsd type: DurationType
    tl::optional<std::string> identity_staleness;
    /// \brief Indicates the position uncertainty to be compared to the position
    /// uncertainty in the Entity message. This element represents the positional
    /// accuracy of the target. It is the area, in square data miles, within which
    /// it is assessed that there is a 95% probability that the target lies. The
    /// value given in this element can be compared to either the Quality element
    /// of the target or a calculated uncertainty area for the target based on its
    /// uncertainty ellipse.
    tl::optional<float> position_uncertainty;
    /// \brief Indicates the position staleness to be compared to the kinematic staleness
    /// in the Entity message.
    /// xsd type: DurationType
    tl::optional<std::string> position_staleness;
    /// \brief Indicates a value priority/rank to be compared to the priority/rank in
    /// PrioritizationList referencing the Entity.
    tl::optional<PrioritizationListValueType> prioritization_list;
    /// \brief Indicates behaviors, activities, use of capabilities, etc. to be compared
    /// to those of the battlespace object associated with the Entity.
    tl::optional<BehaviorType> behavior;
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 003.000.003.000
struct EntityComparativeType {
    /// \brief Indicates a characteristic/element value to be used to compare to the
    /// corresponding value of the Entity or related message.
    EntityCharacteristicType characteristic = {};
    /// \brief Indicates the logical comparator to use when comparing the target (Entity
    /// or related message) Characteristic to the Response Characteristic. The
    /// logical expression is: (target Characteristic) (Comparator) (Response
    /// Characteristic). When the logical expression is TRUE then the parent
    /// TargetClause instance is TRUE.
    EqualityExpressionEnum comparator = EqualityExpressionEnum::Unspecified;
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 003.001.003.000
struct EntityFilterType {
    /// \brief Indicates a type of Entity designation, established by the Designation
    /// message, required to satisfy the filter.
    tl::optional<DesignationFilterType> designation;  // optional
    /// \brief This element indicates an Entity filter requiring a variable logical
    /// comparator test between a value in an Entity-associated message and the
    /// value given here. Multiple instances are logically ANDed.
    std::vector<EntityComparativeType> characteristics = {};
    /// \brief Indicates a specific EntityID that is required to match the filter. If
    /// omitted, any EntityID satisfies the filter. Multiple instances are
    /// logically ORed.
    std::vector<EntityID_Type> entity_id = {};
    /// \brief Indicates an Entity source that is required to match the filter. If
    /// omitted, any Entity source satisfies the filter. Multiple instances are
    /// logically ORed. List size for this element is based on "Select All That
    /// Apply" condition.
    std::vector<EntitySourceEnum> source = {};
    /// \brief Indicates a zone the Entity must fall within to satisfy the filter.
    /// Multiple instances are logically ORed.
    std::vector<GeoFiltersQueryType> geo_filter = {};
    /// \brief Indicates a zone the Entity must fall within to satisfy the filter.
    /// Multiple instances are logically ORed.
    std::vector<OrbitalFiltersQueryType> orbital_filter = {};
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 003.000.003.000
struct SystemCharacteristicType {
    // oneof choice
    /// \brief Indicates an identity to be compared to the identity of the System.
    tl::optional<EntityIdentityChoiceType> identity;
    /// \brief Indicates the position uncertainty to be compared to the position
    /// uncertainty of the System's kinematics. This element represents the
    /// positional accuracy of the target. It is the area, in square data miles,
    /// within which it is assessed that there is a 95% probability that the target
    /// lies. The value given in this element can be compared to either the Quality
    /// element of the target or a calculated uncertainty area for the target based
    /// on its uncertainty ellipse.
    tl::optional<float> position_uncertainty;
    /// \brief Indicates the position staleness to be compared to the kinematic staleness
    /// of the System's kinematics.
    /// xsd type: DurationType
    tl::optional<std::string> position_staleness;
    /// \brief Indicates a value priority/rank to be compared to the priority/rank in
    /// PrioritizationList referencing the System.
    tl::optional<PrioritizationListValueType> prioritization_list;
    /// \brief Indicates behaviors, activities, use of capabilities, etc. to be compared
    /// to those of the battlespace object associated with the System.
    tl::optional<BehaviorType> behavior;
};

/// \brief See annotations in child elements and messages/elements that use this type
