/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct MA_ActionMDT {
    /// \brief Indicates a unique ID assigned to the Action. Minor updates to the Action
    /// can be indicated by an update of the value in the child Version element.
    /// More significant updates, replacements, etc. might warrant a new instance
    /// with a different child UUID value.
    ActionID_Type action_id = {};
    /// \brief Indicates the type of Action; the type of behavior to be performed when the
    /// Action is executed. An Action is a representation of an operational
    /// planning sentence/statement whose most complex form is: 1. Do [ActionType]
    /// within [ActionConstraints] to [TargetObject] within
    /// [TargetObjectConstraint] to/on/against/toward [SecondaryObject] Many other
    /// forms are also possible, including: 2. do [ActionType] 3. do [ActionType]
    /// to [TargetObject] 4. do [ActionType] to [TargetObject] doing
    /// [TargetObjectConstraint] to [SecondaryObject].
    ActionTypeEnum action_type = ActionTypeEnum::Unspecified;
    /// \brief Indicates constraints on the Action. The constraint type used here is
    /// common to all Requirement types: Effect, Action, Task, [Capability]Command,
    /// Response. Requirement constraints can be 1) given in a [Requirement]
    /// message, 2) overridden as a planning input in a [Requirement]PlanCommand
    /// message, 3) further refined/overridden during plan creation and reported in
    /// a [Requirement]Plan message to inform subsequent planning or execution. See
    /// sibling ActionType element annotation for an overall description of Action
    /// structure.
    tl::optional<MA_RequirementConstraintsType> action_constraints;  // optional
    /// \brief Indicates guidance on planning and C2 of the Action.
    tl::optional<RequirementGuidanceType> action_guidance;  // optional
    /// \brief Used to provide supporting data specific to the different action types.
    tl::optional<MA_UniqueActionDataType> category_unique_data;  // optional
    /// \brief Indicates the target of the Action; the object the Action will be done to
    /// or for. If omitted, the Action places no explicit limitation on which
    /// TargetObject it can be done to. See sibling ActionType element annotation
    /// for an overall description of Action structure. Note that the term "target"
    /// is used in a general sense. For some Requirement types, a more suitable
    /// term might be "subject", "point", "location", etc. For example, the
    /// "target" of a COVER Action could be a blue/friendly System.
    std::vector<IdentityKindInstanceType> target_object = {};
    /// \brief Indicates constraints "on" the TargetObject that must be satisfied before
    /// the Action can be done to or for it. See sibling ActionType element
    /// annotation for an overall description of Effect structure.
    tl::optional<RequirementTargetConstraintsType> target_object_constraints;  // optional
    /// \brief Indicates a thing the sibling TargetObject must act on/against/toward to
    /// make the Action applicable. See sibling ActionType element annotation for
    /// an overall description of Action structure.
    std::vector<IdentityKindInstanceType> secondary_object = {};
    /// \brief Indicates traceability and other metadata associated with the Action.
    tl::optional<RequirementMetadataType> metadata;  // optional
};

