/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 003.000.003.000
struct PlanningByCaseTriggerType {
    // oneof choice
    /// \brief This trigger refers to a new Capability or SubCapability which becomes
    /// available or a previously failed Capability which has been restored.
    tl::optional<CapabilityTaxonomyType> capability_added;
    /// \brief This trigger refers to a failure of a Capability and/or SubCapability
    /// needed to perform a Requirement.
    tl::optional<CapabilityTaxonomyType> capability_failure;
    /// \brief This trigger refers to lost comms.
    tl::optional<CommsLostTriggerDataType> comms_lost;
    /// \brief This trigger refers to a situation where the designated DMPIs exceed those
    /// initially reserved for the Task, if this creates a shortage for other
    /// assigned Tasks.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> dmpi_over_designation;
    /// \brief This trigger refers to a situation where the designated DMPIs are less than
    /// those initially reserved for the task, and if weapons not designated can be
    /// used to perform previous unallocated tasks.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> dmpi_under_designation;
    /// \brief This trigger refers to a low remaining endurance condition such as low fuel
    /// or battery power. This trigger can further be specialized by the definition
    /// of the Endurance thresholds to define the trigger.
    tl::optional<EnduranceType> endurance_low;
    /// \brief This trigger refers to a vehicle that has deviated from the planned route
    /// to such a degree that a replan is required.
    tl::optional<ThresholdOffRouteTriggerDataType> off_route;
    /// \brief This trigger refers to the proximity of two items (Systems, Entities or
    /// other items) that exceeded a minimum geospatial separation limit as
    /// specified in OpRouting messages.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> proximity_conflict;
    /// \brief This trigger refers to the location of a DMPI, updated LAR calculations or
    /// other changes that have resulted in the planned release point for a weapon
    /// falling outside the weapon LAR.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> release_point_outside_lar;
    /// \brief This trigger refers to a route that exceeded a minimum geospatial
    /// separation limit with another item or items. The separation is between a
    /// planned/navigated route and other routes or conflicting items as specified
    /// in OpRouting messages.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> route_conflict;
    /// \brief This trigger refers to vulnerability due to exposure along the route with
    /// and without suppression.
    tl::optional<PlanVulnerabilityType> route_vulnerability;
    /// \brief This trigger refers to a system state transition, as indicated by the
    /// SystemStatus message.
    tl::optional<SystemStateFilterType> system_state_change;
    /// \brief This trigger indicates a new Requirement.
    tl::optional<RequirementTriggerType> requirement_added;
    /// \brief This trigger indicates a Requirement that cannot be planned/performed
    /// because a Requirement it is dependent on cannot be planned/performed.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> requirement_dependency_failed;
    /// \brief This trigger refers to a Requirement execution state transition to DROPPED,
    /// as indicated by execution status message for the Requirement (EffectStatus,
    /// TaskStatus, etc.).
    tl::optional<RequirementTriggerType> requirement_dropped;
    /// \brief This trigger refers to a Requirement execution state transition to FAILED,
    /// as indicated by execution status message for the Requirement (EffectStatus,
    /// TaskStatus, etc.).
    tl::optional<RequirementFailedTriggerType> requirement_failed;
    /// \brief This trigger refers to a change to a Requirement that impacts an existing
    /// plan. For example, a change of the position of the target of the
    /// Requirement.
    tl::optional<RequirementTriggerType> requirement_change;
    /// \brief This trigger a Requirement that is not expected to meet its timing
    /// constraints.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> requirement_timing;
    /// \brief This trigger refers to an OpZone conflicts with the current plan.
    tl::optional<ZoneViolationTriggerDataType> zone_violation;
    /// \brief This trigger refers to the position along a future
    /// planned/predicted/propagated orbit for a spacecraft exceeding a minimum
    /// geospatial separation limit with another item or items.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> orbit_conflict;
    /// \brief This trigger refers to a spacecraft that has deviated from its planned
    /// orbit to such a degree that a replan is required.
    tl::optional<ThresholdOffOrbitTriggerDataType> off_planned_orbit;
    /// \brief This trigger refers to a low remaining endurance condition such as low fuel
    /// or battery power. This trigger can further be specialized by setting
    /// trigger thresholds in descendant elements.
    tl::optional<SatelliteEnduranceType> spacecraft_endurance_low;
    /// \brief This trigger refers to the proximity of two spacecraft (Systems, Entities
    /// or other space items) that exceeded a minimum geospatial separation limit.
    /// Monitoring for this trigger should be based on current position of live
    /// items, not planned/predicted/propagated positions of Systems; see sibling
    /// OrbitConflict element.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> spacecraft_proximity_conflict;
    /// \brief This trigger indicates planning triggered by a Response and/or ResponsePlan.
    tl::optional<ResponseID_Type> response_id;
};

