/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 003.000.003.000
struct RequirementExecutionPolicyType {
    /// \brief This element indicates whether or not approval is required by default for
    /// Requirement execution. The default can be overridden in specific conditions
    /// as indicated by the sibling ByRequirementPolicy element. For example, an
    /// ApprovalPolicy could use this element to indicate that approval is required
    /// before executing Requirements by default and then use the sibling
    /// ByRequirementPolicy element to specify conditions when execution approval
    /// is not required such as for EA and Collection Tasks. Alternately, this
    /// element could indicate that approval is not required by default and then
    /// use ByRequirementPolicy to specify conditions when is required, such as for
    /// Strike Tasks. Creators of this message are expected to carefully avoid
    /// creating logically inconsistent policies and therefore no guidance is given
    /// on deconflicting illogical instances. For example, an ApprovalPolicy that
    /// indicates approval is not required by default with conflicting
    /// ByRequirementPolicy overrides of 1) ApprovalRequired=TRUE for SAR Tasks and
    /// 2) ApprovalRequired=FALSE for SAR Tasks would be considered illogical.
    tl::optional<DefaultResponseType> default_response;  // optional
    /// \brief Indicates whether or not approval is required for a given Requirement type,
    /// overriding the default Requirement execution approval policy given in the
    /// sibling DefaultResponse element. See the annotations in the sibling
    /// DefaultResponse element for an overview of how it relates to this element.
    /// If multiple instances are given, each should be of a different Requirement
    /// type as indicated by the child Requirement element.
    std::vector<ByRequirementPolicyType> by_requirement_policy = {};
};

