/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct MA_ApprovalPolicyMDT {
    tl::optional<DataRecordInstanceID_Type> data_record_instance_id;  // from DataRecordBaseType  // optional
    /// \brief Indicates the unique ID of the approval policy.
    ApprovalPolicyID_Type approval_policy_id = {};
    /// \brief Indicates a set of approval policies for the results of planning activities.
    std::vector<MA_PlanPolicyType> plans = {};
    /// \brief Indicates approval policies which govern Plan Activation commands.
    std::vector<MA_PlanActivationPolicyType> plan_activation = {};
    /// \brief Indicates which Requirement (Effect, Action, Task, [Capability]Command,
    /// Response) execution/performance related activities require approval.
    tl::optional<RequirementExecutionPolicyType> requirement_execution;  // optional
    /// \brief Indicates the geospatial zone and optionally time/date span or spans when
    /// the policy is active. For task allocation, the policy is applicable to
    /// allocations that 1) complete within the time/date span and 2) include Task
    /// or Tasks whose target falls within the zone, regardless of when the Task
    /// will be executed. For route planning, the policy is applicable to route
    /// plans with segments that fall within the zone during the time/date span,
    /// regardless of when the route plan was completed or the target of Tasks
    /// associated with the segments. For task execution, the policy is applicable
    /// to Tasks that 1) are scheduled to complete within the time/date span and 2)
    /// have a target which falls within the zone. This element supersedes the
    /// sibling Expires element.
    tl::optional<TimedZoneType> timed_zone;  // optional
    /// \brief Indicates the time and date when the policy expires. The policy is
    /// applicable to task allocation and route planning activities completed prior
    /// to this time. The policy is applicable to task execution activities
    /// initiated prior to this time. When the sibling TimedZone element is used,
    /// the time spans specified there supersede this element.
    /// xsd type: DateTimeType (pattern .+Z)
    std::string expires = {};  // optional
    /// \brief Allows the creator of the approval policy to specify the source or
    /// motivation for this ApprovalPolicy such as ATO, ACO, etc.
    tl::optional<MissionTraceabilityType> mission_traceability;  // optional
};

