/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 003.001.003.001
struct EntitySourceIdentifierType {
    // oneof choice
    /// \brief Indicates an EOB record from which this Entity originated.
    tl::optional<EOB_RecordID_Type> eob_record_id;
    /// \brief Indicates the ID of an Entity-like object in an external system (non-UCI)
    /// which this Entity was derived from. For example, this element could
    /// indicate a MIL-STD-6016 track number.
    tl::optional<EntityExternalType> external_identifier;
    /// \brief Indicates the Entity is an output of a fusion service and provides
    /// references to a fusion input Entity that fused/contributed to it.
    tl::optional<EntitySourceIdentifierType_Fusion_List> fusion;
    /// \brief This element represents a non-Entity UCI object/message ID from which this
    /// Entity was derived. Most elements of type ID_Type infer a specific ID type.
    /// This element is different in that any UCI ID type is allowed. This will
    /// support moving target date from Tasks (possibly specified by ground forces)
    /// to Entities in order to designate DMPIs. It will also support linkage to a
    /// generic event or ID. Examples include; association of an entity with an
    /// operator location of interest. Locations are maintained independently
    /// between OLI and entity, indication that this entity was created as a result
    /// of completing a task, or a command which generated the entity.
    tl::optional<ID_Type> internally_derived_id;
    /// \brief Indicates this Entity is from a Capability source and provides the unique
    /// ID of the Capability instance along with the Capability's internal
    /// reference number/ID that corresponds to this Entity.
    tl::optional<EntityCapabilitySourceType> capability;
    /// \brief Indicates the unique ID of the Product from which the Entity was derived.
    tl::optional<EntitySourceIdentifierType_ProductMetadataID_List> product_metadata_id;
    /// \brief UUID of the operator associated with this entity.
    tl::optional<OperatorID_Type> operator_id;
    /// \brief Indicates the SOB satellite record from which this Entity was derived.
    tl::optional<SOB_SatelliteRecordID_Type> sob_satellite_record_id;
    /// \brief Indicates the ID of the SOB C2 record from which this Entity was derived.
    tl::optional<SOB_C2_RecordID_Type> sob_c2_record_id;
};

/// \brief Indicates the unique ID of an Entity which is eligible for or excluded from
