    tl::optional<IFF_Type> iff_settings;  // optional
    /// \brief Specifies that the vehicle should put itself into a more survivable mode.
    /// Different vehicles will have specific behaviors that reduce the signature
    /// of the vehicle (doors closed, minimal use of flaps, etc.) If this element
    /// is not present then it is assumed that the aircraft being configured has no
    /// survivability mode.
    tl::optional<VehicleSurvivabilityModeEnum> survivability_mode;  // optional
    /// \brief Defines the lost communication contingency timeout. When this timeout value
    /// is exceeded, the AV considers that lost communication has occurred and
    /// begins to perform contingency measures.
    /// xsd type: DurationType
