/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 003.000.003.001
struct SystemStatusMDT {
    /// \brief Identifier that refers to any level of control station or a vehicle.
    SystemID_Type system_id = {};
    /// \brief This element represents the operational state of the system with respect to
    /// active mission activities.
    SystemStateEnum system_state = SystemStateEnum::Unspecified;
    /// \brief Indicates the source of the data in sibling elements. See enumeration
    /// annotations for further details.
    SystemSourceEnum source = SystemSourceEnum::Unspecified;
    /// \brief Indicates the eligibility of this Entity for automated fusion operations by
    /// the Entity's source System/Service and/or fusion tier. FULL indicates that
    /// this Entity, and therefore its contributor Entity or Entities, is fully
    /// eligible for future automated fusion operations. SELECTIVE_EXCLUSION
    /// indicates that the Entity is eligible for future automated fusion
    /// operations excluding merging with the Entity or Entities given in the
    /// sibling CorrelatedEntity element. SELECTIVE_INCLUSION indicates that the
    /// Entity is eligible for future automated fusion operations but only with the
    /// Entity or Entities given in the sibling CorrelatedEntity element. NONE
    /// indicates that this Entity is not eligible for future automated fusion
    /// operations regardless of the associated Entity. This element does not
    /// restrict operator initiated fusion operations via the
    /// EntityManagementRequest.
    tl::optional<EntityFusionEligibilityEnum> fusion_eligibility;  // optional
    /// \brief Identifies resource manufacturer and model. This element can serve as means
    /// to "look-up" a description or model of the System that is described
    /// independent of UCI.
    /// xsd type: VisibleString32Type (pattern [ -~]{0,32})
    std::string model = {};  // optional
    /// \brief This element represents the mission/functional identity of the System. It
    /// is left to applications using UCI to enforce compatibility with the
    /// portions of MIL-STD-6016 or other standards referenced herein.
    tl::optional<SystemIdentityType> identity;  // optional
    /// \brief Indicates the communication state and usage information for this system.
    SystemCommunicationsType communications = {};
    /// \brief The UUID of the operator associated with this system.
    std::vector<OperatorID_Type> operator_id = {};
    /// \brief Indicates a C2 relevant Subsystem of the System.
    std::vector<SubsystemID_Type> subsystem_id = {};
    /// \brief Indicates a C2 relevant Capability of the System.
    std::vector<CapabilityID_Type> capability_id = {};
    /// \brief Indicates a Service that is implemented by the System.
    std::vector<ServiceID_Type> service_id = {};
    /// \brief General status information about the asset.
    tl::optional<PlatformStatusType> platform_status;  // optional
    /// \brief This type contains the connection data needed to communicate with a vehicle
    /// using voice radios.
    tl::optional<VoiceControlType> voice_control;  // optional
    /// \brief This element indicates an activity, that isn't otherwise represented by UCI
    /// Tasks, Capability commands, etc. being performed by the Entity.
    std::vector<ActivityByType> activity_by = {};
    /// \brief The number of entities represented by a single track.
    tl::optional<StrengthType> strength;  // optional
};

