    /// kinematic and action plans. The kinematic and action plans are combined
    /// into sets and given unique IDs. An execution flow may be created by linking
    /// ExecutionPlanSets of different types (e.g. OrbitExecutionPlanSet and
    /// RouteExecutionPlanSet).
    tl::optional<ExecutionSequenceType> execution_sequence;  // optional
    /// \brief Indicates a MissionPlan that is the parent of this MissionPlan.
    std::vector<MissionPlanID_Type> parent_mission_plan_id = {};
    /// \brief Indicates a MissionPlan that is subordinate to this MissionPlan.
    std::vector<MissionPlanID_Type> subordinate_mission_plan_id = {};
    /// \brief When TRUE, indicates the *Plan is to be used only for intermediate planning
    /// purposes. It will eventually be replaced/superseded by another *Plan or be
    /// discarded/abandoned. *Plans with this flag should only be used when
    /// explicitly referenced by other messages. These *Plans should never: trigger
    /// functionality, be subject to approvals, be activated, etc.
