/// \brief A generic type that allows the specification of incremental status. Usually
/// populated when reporting a status of "Processing".
/// uci_version: 001.000.000.000
struct CompletionStatusType {
    /// \brief Estimated time that the process will be completed.
    /// xsd type: DateTimeType (pattern .+Z)
    std::string estimated_time_complete = {};  // optional
    /// \brief Estimated percentage of the process that has been completed.
    /// xsd type: PercentType
    tl::optional<double> estimated_percent_complete;  // optional
    /// \brief Record of the actual time that the operation started.
    /// xsd type: DateTimeType (pattern .+Z)
    std::string actual_time_started = {};  // optional
    /// \brief Record of the actual time that operation completed.
    /// xsd type: DateTimeType (pattern .+Z)
    std::string actual_time_complete = {};  // optional
    /// \brief Text field to communicate a description of the status to the operator.
    /// xsd type: VisibleString1024Type (pattern [ -~]{0,1024})
    std::string description = {};  // optional
};

/// \brief When processing multiple items (e.g. vehicle mission plans, route
/// vulnerability assessments), this represents an item that failed to process
/// successfully.
/// uci_version: 001.000.002.000
struct IncompleteProcessingType {
    /// \brief Indicates the unique ID of the item (message, System, Task, etc.) that
    /// failed to process. For example, if information for a particular vehicle was
    /// incomplete then the vehicle's SystemID might be given here to indicated
    /// planning/processing for that vehicle is/was incomplete.
    ID_Type incomplete_item_id = {};
    /// \brief Indicates the reason why the processing on the item failed and/or generally
    /// cannot be completed satisfactorily. See enumeration annotations for further
    /// details.
    CannotComplyEnum reason = CannotComplyEnum::Unspecified;
    /// \brief A human-readable text description of the reason the processing can not
    /// complete satisfactorily.
    /// xsd type: VisibleString1024Type (pattern [ -~]{0,1024})
    std::string description = {};  // optional
};

/// \brief Indicates the common status information for all *PlanCommands.
/// uci_version: 002.000.002.000
struct PlanCommandStatusType {
    /// \brief Indicates the status of the command.
    CommandProcessingStateEnum command_processing_state = CommandProcessingStateEnum::Unspecified;
    /// \brief Indicates details regarding the reason for and/or a contributing factor to
    /// the sibling CommandProcessingState element. This element is only expected
    /// when the Command is in a potentially undesirable state such as rejected,
    /// canceled or accepted with less than optimum results expected.
    tl::optional<CannotComplyType> command_processing_state_reason;  // optional
    /// \brief Indicates the status of the command.
    ProcessingStatusEnum command_status = ProcessingStatusEnum::Unspecified;
    /// \brief Indicates actual and predicted metrics for completion of the command.
    tl::optional<CompletionStatusType> completion_status;  // optional
    /// \brief Indicates items associated with command processing that failed to complete.
    /// For example if a particular required Capability wasn't available, it could
    /// be referenced here. This element/type is highly flexible. It can reference
    /// almost any message/concept in UCI as a planning issue. The wide range of
    /// messages/concepts it can reference makes it 1) difficult to use as a basis
    /// for software/services to resolve the issue but 2) an excellent general
    /// method for processing algorithms to convey issues to operators. This
    /// element shouldn't be used to report processing issues/results that are more
    /// directly indicated by other processing status elements. For example, for
    /// planning processing, other elements focus specifically on per-Requirement
    /// allocation results therefore this element shouldn't be used for
    /// per-Requirement allocation results.
    std::vector<IncompleteProcessingType> incomplete_item = {};
};

