/// \brief See the annotation in the associated message for an overall description of
/// the message and this type.
/// uci_version: 000.000.000.000
struct MA_PlanningFunctionMDT {
    /// \brief Indicates a unique ID, assigned to this PlanningFunction.
    PlanningFunctionID_Type planning_function_id = {};
    /// \brief Indicates the unique ID of the System whose planning functions are being
    /// reported.
    SystemID_Type system_id = {};
    /// \brief Indicates planning interfaces supported by the System. A supported
    /// interface isn't necessarily enabled currently; see the PlanningStatus
    /// message for current status/configuration of control interfaces advertised
    /// here.
    std::vector<PlanningInterfacesType> planning_interfaces = {};
    /// \brief This element is used to describe the details of planning
    /// interfaces/messages, specifically *PlanCommand interfaces of a System. It
    /// provides discoverability of distinct planning process instances along with
    /// the functional scope and output *Plan type or types. A planning
    /// interface/process described here can only be invoked when the sibling
    /// Interfaces element indicates it is enabled. Planning processes are
    /// dynamically discoverable because Systems tend to have widely varying
    /// planning functionality. Decomposing planning into discrete processes allows
    /// planning functionality to be distributed across a service oriented system
    /// of systems. Making planning processes discoverable encourages
    /// planning-related services at multiple levels in a C2 hierarchy to adapt to
    /// and simultaneously support Systems with different planning functionality
    /// and processes.
    tl::optional<MA_PlanningInterfaceDetailsType> planning_interface_details;  // optional
    /// \brief Indicates capabilities of the System to perform plan activation
    /// autonomously. Plan activations can be performed either at the MissionPlan
    /// or SubPlan level.
    tl::optional<SupportedPlanActivationAutonomyType> plan_activation_autonomy_details;  // optional
    /// \brief This element is used to describe the details of scoring interfaces/messages
    /// summarized in the sibling Interfaces element. It provides discoverability
    /// of distinct scoring process instances along with the functional scope. A
    /// scoring interface/process described here can only be invoked when the
    /// sibling Interfaces ActivationState element indicates it is enabled. Plan
    /// Scoring processes are dynamically discoverable because Systems tend to have
    /// varying scoring algorithms. Decomposing plan scoring into discrete
    /// processes allows scoring functionality to be distributed across a service
    /// oriented system of systems.
    tl::optional<PlanScoringProcessType> scoring_interface_details;  // optional
};

