/// \brief Indicates the settings/usage of a planning process for autonomous planning.
/// uci_version: 000.000.000.000
struct MA_AutonomousPlanCommandType {
    /// \brief Indicates the unique ID of the planning process whose autonomous invocation
    /// is described the sibling elements. Planning process are declared in the
    /// ControlStatus message.
    PlanningProcessID_Type planning_process_id = {};
    /// \brief Indicates existing types of *Plans that can be used as constraints when
    /// invoking the planning process indicated by the sibling PlanningProcessID.
    /// The types of *Plans indicated here should be consistent with those
    /// supported by the planning process as indicated in the ControlStatus message.
    tl::optional<AutonomousPlanningConstrainingPlansType> constraining_plans;  // optional
    /// \brief Indicates existing plans of another System that constrain planning. One for
    /// each descendant ConstraintUsage.
    std::vector<AutonomousPlanningOtherSystemConstrainingPlansType> other_system_constraining_plans = {};
    /// \brief Indicates the specific Plan parts of the sibling PlanningType that the
    /// System can produce and include in the output Plan. The child choice in this
    /// element should match the sibling PlanningType. When omitted, the System can
    /// produce all of the Plan parts for the sibling PlanningType.
    tl::optional<MA_PlanPartsType> output_plan_parts;  // optional
    /// \brief In some cases, the commanding service or HMI may not want to receive the
    /// planning process summarized in a MissionPlan message. If TRUE, the results
    /// will be published in individual *Plan messages and summarized in a
    /// published MissionPlan message. If FALSE, the results will be published in
    /// individual *Plan messages without a summary MissionPlan message.
    bool results_in_mission_plan = false;
    /// \brief Indicates the state to use for the corresponding element in the
    /// PlanCommand when invoking the planning process.
    bool for_planning_use_only = false;
};

/// \brief See annotations in child elements and messages/elements that use this type
