/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct MA_InertialStateType {
    /// \brief Physical location of the referenced item in geospatial coordinates. The use
    /// of the timestamp in this context represents the time the positional data
    /// was last measured.
    Point4D_Type position = {};
    /// \brief Uncertainty of the physical location of the referenced item.
    tl::optional<UncertaintyType> position_uncertainty;  // optional
    /// \brief Vehicle's velocity in the current operating domain of the system. Air
    /// vehicle components are in True Air Speed.
    tl::optional<Velocity3D_Type> domain_velocity;  // optional
    /// \brief Indicates the air vehicle's calibrated airspeed as a scalar magnitude,
    /// derived from pilot-static measurements and corrected for instrument and
    /// position error.
    /// xsd type: SpeedType
    tl::optional<double> calibrated_airspeed;  // optional
    /// \brief Indicates the unitless ratio of the air vehicle's true airspeed to the
    /// speed of sound in the surrounding medium.
    /// xsd type: MachType
    tl::optional<double> mach;  // optional
    /// \brief Representation of the vehicle's ground velocity as directional speed
    /// components.
    tl::optional<Velocity2D_Type> ground_velocity;  // optional
    /// \brief The vehicle's acceleration in the current operating domain of the system.
    tl::optional<Acceleration3D_Type> domain_acceleration;  // optional
    /// \brief Euler Angle Sequence describing the orientation of the vehicle in the order
    /// yaw, pitch, roll. The angles are given in a locally level, North-East-Down
    /// coordinate system centered on the vehicle.
    tl::optional<OrientationType> orientation;  // optional
    /// \brief Euler Angle Sequence describing the rate of orientation change of the
    /// vehicle in the order yaw, pitch, roll. The angles are given in a locally
    /// level, North-East-Down coordinate system centered on the vehicle.
    tl::optional<OrientationRateType> orientation_rate;  // optional
    /// \brief The level of geodetic position uncertainty as estimated by the unit
    /// reporting its position, where higher number indicates lower uncertainty and
    /// better quality.
    /// xsd type: Link16_PositionQualityType
    tl::optional<uint32_t> link16_position_quality;  // optional
};

