/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 003.001.003.000
struct MA_PlannedSequentialTriggerType {
    /// \brief Indicates the response to be taken when the triggering conditions of the
    /// Option are satisfied.
    ResponseID_Type response_id = {};
    /// \brief Indicates a trigger based on an Entity with filters/preconditions that must
    /// be met before the Option is triggered. All immediate child element filters
    /// must be met before the Option is triggered; child elements are logically
    /// ANDed. If a child element is omitted then any Entity matches that element's
    /// filter..
    tl::optional<EntityFilterType> entity;  // optional
    /// \brief Indicates a trigger based on a System with filters/preconditions that must
    /// be met before the Option is triggered. All immediate child element filters
    /// must be met before the Option is triggered; child elements are logically
    /// ANDed. If a child element is omitted then any System matches that element's
    /// filter.
    tl::optional<SystemFilterType> system;  // optional
    /// \brief Indicates a trigger based on a Requirement with filter/preconditions that
    /// must be met before the Option is triggered. All immediate child element
    /// filters must be met before the Option is triggered; child elements are
    /// logically ANDed. If a child element is omitted then any Requirement matches
    /// that element's filter.
    tl::optional<RequirementFilterType> requirement;  // optional
    /// \brief Indicates a trigger based on a Requirement with filters/preconditions that
    /// must be met before the Option is triggered. All immediate child element
    /// filters must be met before the Option is triggered; child elements are
    /// logically ANDed. If a child element is omitted then any Requirement matches
    /// that element's filter.
    tl::optional<AccessAssessmentFilterType> access_assessment;  // optional
    /// \brief Indicates a trigger based on an OperatorLocationOfInterest (OLOI) with
    /// filters/preconditions that must be met before the Option is triggered. All
    /// immediate child element filters must be met before the Option is triggered;
    /// child elements are logically ANDed. If a child element is omitted then any
    /// OLOI matches that element's filter.
    tl::optional<OperatorLocationOfInterestClauseType> oloi;  // optional
    /// \brief Indicates a ResponseCommand message as the trigger.
    tl::optional<ResponseID_Type> response_command_id;  // optional
    /// \brief Indicates a trigger based on any UCI message, filtered/constrained by a
    /// query filter. Filter elements with cardinality greater than 1 are logically
    /// ORed. Sibling filter elements are logically ANDed.
    tl::optional<QueryMessageType> any_message;  // optional
    /// \brief This trigger refers to a new Capability or SubCapability which becomes
    /// available or a previously failed Capability which has been restored.
    tl::optional<CapabilityTaxonomyType> capability_added;  // optional
    /// \brief This trigger refers to a failure of a Capability and/or SubCapability
    /// needed to perform a Requirement.
    tl::optional<CapabilityTaxonomyType> capability_failure;  // optional
    /// \brief This trigger refers to lost comms.
    tl::optional<CommsLostTriggerDataType> comms_lost;  // optional
    /// \brief This trigger refers to a low remaining endurance condition such as low fuel
    /// or battery power. This trigger can further be specialized by the definition
    /// of the Endurance thresholds to define the trigger.
    tl::optional<EnduranceType> endurance_low;  // optional
    /// \brief This trigger refers to a vehicle that has deviated from the planned route
    /// to such a degree that a replan is required.
    tl::optional<ThresholdOffRouteTriggerDataType> off_route;  // optional
    /// \brief This trigger refers to the proximity of two items (Systems, Entities or
    /// other items) that exceeded a minimum geospatial separation limit as
    /// specified in OpRouting messages.
    tl::optional<EntityFilterType> proximity_conflict;  // optional
    /// \brief This trigger refers to a route that exceeded a minimum geospatial
    /// separation limit with another item or items. The separation is between a
    /// planned/navigated route and other routes or conflicting items as specified
    /// in OpRouting messages.
    tl::optional<RoutePlanID_Type> route_conflict_id;  // optional
    /// \brief This trigger refers to vulnerability due to exposure along the route with
    /// and without suppression.
    tl::optional<PlanVulnerabilityType> route_vulnerability;  // optional
    /// \brief This trigger refers to a system state transition, as indicated by the
    /// SystemStatus message.
    tl::optional<SystemStateFilterType> system_state_change;  // optional
    /// \brief This trigger indicates a new Requirement.
    tl::optional<RequirementTriggerType> requirement_added;  // optional
    /// \brief This trigger refers to a Requirement execution state transition to DROPPED,
    /// as indicated by execution status message for the Requirement (EffectStatus,
    /// TaskStatus, etc.).
    tl::optional<RequirementTriggerType> requirement_dropped;  // optional
    /// \brief This trigger refers to a Requirement execution state transition to FAILED,
    /// as indicated by execution status message for the Requirement (EffectStatus,
    /// TaskStatus, etc.).
    tl::optional<RequirementFailedTriggerType> requirement_failed;  // optional
    /// \brief This trigger refers to a change to a Requirement that impacts an existing
    /// plan. For example, a change of the position of the target of the
    /// Requirement.
    tl::optional<RequirementTriggerType> requirement_change;  // optional
    /// \brief This trigger refers to an OpZone conflicts with the current plan.
    tl::optional<ZoneViolationTriggerDataType> zone_violation;  // optional
    /// \brief This trigger refers to the position along a future
    /// planned/predicted/propagated orbit for a spacecraft exceeding a minimum
    /// geospatial separation limit with another item or items.
    tl::optional<OrbitPlanID_Type> orbit_conflict_id;  // optional
    /// \brief This trigger refers to a spacecraft that has deviated from its planned
    /// orbit to such a degree that a replan is required.
    tl::optional<ThresholdOffOrbitTriggerDataType> off_planned_orbit;  // optional
    /// \brief Indicates a trigger based on a weather condition present (i.e. temperature,
    /// precipitation amount) with filters/preconditions that must be met before
    /// the Option is triggered. All immediate child element filters must be met
    /// before the Option is triggered; child elements are logically ANDed. If a
    /// child element is omitted, then that field need not be considered as a
    /// condition to be met/checked.
    tl::optional<MA_InertialStateType> vehicle_state;  // optional
    /// \brief Indicates a trigger based on an vehicle parameter with
    /// filters/preconditions that must be met before the Option is triggered. All
    /// immediate child element filters must be met before the Option is triggered;
    /// child elements are logically ANDed. If a child element is omitted, then
    /// that field need not be considered as a condition to be met/checked.
    tl::optional<WeatherReportGridDataType> weather;  // optional
    /// \brief Indicates a trigger based on a designated waypoint in the route. It is
    /// generally used for points associated with Actions such as task
    /// "transitions", changes in acceleration, changes in speed, changes in
    /// altitude, etc.
    tl::optional<WayPointType> way_point;  // optional
    /// \brief Indicates a trigger based on a time value where a trigger will occur.
    /// xsd type: TimeType (pattern .+Z)
    std::string time = {};  // optional
};

