/// \brief This type is used to specify a set of constraints that constrain when a PO
/// or AO sensor can start collecting the requested image data.
/// uci_version: 001.000.000.001
struct OpticalCollectionConstraintsType {
    tl::optional<AngleHalfPairType> map_angle_constraints;  // from CollectionConstraintsType  // optional
    tl::optional<AngleQuarterPairType> grazing_angle_constraints;  // from CollectionConstraintsType  // optional
    tl::optional<AnglePairType> look_angle_constraints;  // from CollectionConstraintsType  // optional
    tl::optional<AngleHalfPairType> elevation_angle_constraints;  // from CollectionConstraintsType  // optional
    tl::optional<SlantRangeConstraintsType> slant_range_constraints;  // from CollectionConstraintsType  // optional
    tl::optional<CollectionPatternEnum> collection_pattern;  // from CollectionConstraintsType  // optional
    /// \brief The angle from the target plane at intersection of the optical line of
    /// sight with the earth's surface at the time of the first image line.
    tl::optional<AngleHalfPairType> sun_elev_angles;  // optional
    /// \brief The angle from True North clockwise (as viewed from space) at the time of
    /// the first image line.
    tl::optional<AnglePairType> sun_azimuth_angles;  // optional
    /// \brief The rate at which the sensor look-point moves across the terrain. This is
    /// only applicable to area or line targets.
    /// xsd type: SpeedType
    tl::optional<double> sweep_speed;  // optional
    /// \brief The orientation of the gimbal with respect to its reference frame.
    tl::optional<GimbalOrientationPairType> gimbal_orientation;  // optional
};

