/// \brief This type is used to specify a set of constraints that constrain when a PO
/// or AO sensor can start collecting the requested image data.
/// uci_version: 001.000.000.001
struct PO_CollectionConstraintsSettingsType {
    /// \brief True Map Angle. The true map angle is defined in the Northeast Down (NED)
    /// coordinate system with the origin at the aircraft (aircraft local NED) as
    /// the angle between the scene entry line of sight and the instantaneous
    /// aircraft track heading vector. The aircraft track heading vector is
    /// obtained by rotating the north unit vector of the aircraft local NED
    /// coordinate system in the aircraft local NE plane through the aircraft track
    /// heading angle. This angle is always positive. This field is the new
    /// settings for this constraint.
    tl::optional<PO_AngleConstraintControlsType> map_angle;  // optional
    /// \brief The angle at the target between the plane of the terrain and the line of
    /// sight to the sensor. If the slope of the terrain is zero, this element is
    /// equivalent to the sibling ElevationAngleConstraints. This field is the new
    /// settings for this constraint.
    tl::optional<PO_AngleConstraintControlsType> grazing_angle;  // optional
    /// \brief The angle from true north to the line-of-sight vector from the sensor to
    /// the target tangent plane. This field is the new settings for this
    /// constraint.
    tl::optional<PO_AngleConstraintControlsType> look_angle;  // optional
    /// \brief The angle at the target between the flat surface (ellipsoid surface
    /// ignoring terrain) and the line of sight to the sensor. If the slope of the
    /// terrain is zero, this element is equivalent to the sibling
    /// GrazingAngleConstraints. This field is the current settings for this
    /// constraint.
    tl::optional<PO_AngleConstraintControlsType> elevation_angle;  // optional
    /// \brief Distance from the sensor reference point (e.g. aperture reference point) to
    /// the ground reference point. This field is the new settings for this
    /// constraint.
    tl::optional<PO_SlantRangeConstraintControlsType> slant_range;  // optional
    /// \brief This element defines the type of pattern that a vehicle should use to
    /// collect over a large area. This can be specified when creating Tasks to
    /// collect over OpZones, ZoneTargets, Entities (which have been specified as
    /// zones), etc. This field is the new settings for this constraint.
    tl::optional<PO_CollectionPatternConstraintControlsType> collection_pattern;  // optional
    /// \brief The angle from the target plane at intersection of the optical line of
    /// sight with the earth's surface at the time of the first image line. This
    /// field is the new settings for this constraint.
    tl::optional<PO_AngleConstraintControlsType> sun_elev_angles;  // optional
    /// \brief The angle from True North clockwise (as viewed from space) at the time of
    /// the first image line. This field is the new settings for this constraint.
    tl::optional<PO_AngleConstraintControlsType> sun_azimuth_angles;  // optional
    /// \brief The rate at which the sensor look-point moves across the terrain. This is
    /// only applicable to area or line targets. This field is the new settings for
    /// this constraint.
    tl::optional<PO_SweepSpeedConstraintControlsType> sweep_speed;  // optional
    /// \brief The orientation of the gimbal with respect to the reference frame.
    tl::optional<PO_GimbalOrientationConstraintType> gimbal_orientation;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
