    std::string platform_call_sign = {};  // optional
    /// \brief Indicates the mode of operations of the event portrayed in metadata.
    tl::optional<MISP_OperationalModeEnum> operational_mode;  // optional
    /// \brief This metadata element identifies the classification or marking system used
