/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 001.000.000.000
struct AirVolumeSensorReferencedType {
    /// \brief Indicates the commanded azimuth width. It represents the angular width
    /// between the two 3 dB extents of the scan volume.
    /// xsd type: AnglePositiveType
    double azimuth_scan_width = 0.0;
    /// \brief Indicates the commanded azimuth center. For BODY stabilized volumes it is
    /// referenced to the centerline of the platform. For INERTIAL stabilized
    /// volumes it is referenced to true north; clockwise rotation is positive in
    /// both cases.
    /// xsd type: AngleType
    double azimuth_scan_center = 0.0;
    /// \brief Indicates the commanded elevation scan width. It represents the angular
    /// width between the two 3 dB extents of the scan volume.
    /// xsd type: AngleHalfType
    double elevation_scan_width = 0.0;
    /// \brief Indicates the commanded elevation center. For BODY stabilized volumes it is
    /// referenced to the centerline of the platform. For CENTER_ALTITUDE
    /// stabilized volumes it is referenced to the center altitude range pair.
    /// xsd type: AngleHalfType
    double elevation_scan_center = 0.0;
    /// \brief Indicates the maximum range of interest. This will potential affect dwell
    /// times, scan rates, reported Entities, etc.
    /// xsd type: DistanceType
    double max_range_of_interest = 0.0;
    /// \brief Indicates the minimum range of interest. This will potential affect dwell
    /// times, scan rates, reported Entities, etc.
    /// xsd type: DistanceType
    double min_range_of_interest = 0.0;
    /// \brief Center of volume can be stabilized either relative to the centerline of the
    /// aircraft (BODY) or relative to true north (INERTIAL). In either case the
    /// radar will position volume either aligned with the aircraft's current
    /// direction or a particular line of bearing.
    LOS_ReferenceEnum azimuth_scan_stabilization = LOS_ReferenceEnum::Unspecified;
    /// \brief Center of volume can be stabilized either relative to the boresight of the
    /// antenna installation on the aircraft (BODY) or relative to a location
    /// defined by the Elevation Scan Center Altitude Range Pair (CENTER_ALTITUDE).
    /// In either case the radar will position volume either aligned with the
    /// aircraft's current pitch.
    ElevationScanStabilizationEnum elevation_scan_stabilization = ElevationScanStabilizationEnum::Unspecified;
    /// \brief For a center altitude stabilized elevation volumes, this is the center
    /// point around which the volume is stabilized.
    tl::optional<AltitudeRangePairType> elevation_scan_center_altitude_range_pair;  // optional
    /// \brief Indicates whether (TRUE) or not (FALSE) the volume should be stabilized
    /// parallel to the horizon.
    bool roll_stabilized = false;
};

