/// \brief Indicates a set of bounding requirements for the particular collection
/// associated with this command. The subsystem should attempt to satisfy all
/// specified constraints.
/// uci_version: 001.000.002.000
struct SAR_CollectionConstraintsType {
    tl::optional<AngleHalfPairType> map_angle_constraints;  // from CollectionConstraintsType  // optional
    tl::optional<AngleQuarterPairType> grazing_angle_constraints;  // from CollectionConstraintsType  // optional
    tl::optional<AnglePairType> look_angle_constraints;  // from CollectionConstraintsType  // optional
    tl::optional<AngleHalfPairType> elevation_angle_constraints;  // from CollectionConstraintsType  // optional
    tl::optional<SlantRangeConstraintsType> slant_range_constraints;  // from CollectionConstraintsType  // optional
    tl::optional<CollectionPatternEnum> collection_pattern;  // from CollectionConstraintsType  // optional
    /// \brief Specifies the minimum and / or desired imagery Interpretability Rating
    /// Scale (IIRS) value or values for this collection.
    tl::optional<SAR_CollectionConstraintsQualityType> quality;  // optional
    /// \brief Required sweep angle for the continuous spot scene.
    /// xsd type: AngleQuarterType
    tl::optional<double> continuous_spot_angle;  // optional
    /// \brief Specifies the minimum and maximum sensor altitude for the collection.
    tl::optional<AltitudeRangeType> altitude_constraints;  // optional
    /// \brief Indicates the maximum time to be used for the current collection.
    /// xsd type: DurationType
    std::string maximum_mapping_time = {};  // optional
    /// \brief Specifies azimuth constraints for the SAR collection.
    /// xsd type: AngleType
    tl::optional<double> az_subset_fraction;  // optional
    /// \brief Specifies the acceptable tolerance about the commanded map angle.
    /// xsd type: AnglePositiveType
    tl::optional<double> los_buffer_angle;  // optional
    /// \brief This element specifies the number of images to collect along the azimuth of
    /// the collection.
    tl::optional<uint32_t> num_images_azimuth;  // optional
    /// \brief This element specifies the number of images to collect along the range of
    /// the collection.
    tl::optional<uint32_t> num_images_range;  // optional
    /// \brief Used to collect less imagery in azimuth than the default for the mode.
    /// Reduces collection time and resolution and is centered on the middle vector.
    /// xsd type: PercentType
    tl::optional<double> percent_azimuth_collection;  // optional
    /// \brief Max heading deviation before subsystem aborts the scene.
    /// xsd type: AnglePositiveType
    tl::optional<double> heading_deviation_tolerance;  // optional
    /// \brief Max distance that the subsystem can be from the intended flight path before
    /// the scene is aborted.
    /// xsd type: DistanceType
    tl::optional<double> cross_track_deviation_tolerance;  // optional
    /// \brief Used to control the RF emissions associated with this command. If this
    /// field is not populated, the service determines all parameters.
    tl::optional<EmconConstraintType> emcon;  // optional
    /// \brief Relative gain adjustment to be used in post processing stages. Positive
    /// values indicate additional gain to be applied.
    /// xsd type: DecibelType
    tl::optional<double> map_gain_adjustment;  // optional
    /// \brief Provides a location and a bound upon that location for this collection.
    tl::optional<PositionLocationUncertaintyType> ownship_location_constraint;  // optional
};

