/// \brief Defines a line of sight ray in a world inertial or body frame or reference.
/// uci_version: 001.000.000.000
struct AzElReferenceType {
    /// \brief Specifies reference frame for which the sibling Azimuth and Elevation
    /// elements apply.
    LOS_ReferenceEnum reference = LOS_ReferenceEnum::Unspecified;
    /// \brief Indicates the angle from the x-axis towards the y-axis as measured on the
    /// xy plane. When the sibling Reference element indicates INERTIAL, azimuth is
    /// defined as the angle between two lines in a global horizontal plane at the
    /// observation point. The first line is from the observation point to true
    /// north. The second line is from the observation point to the point of
    /// interest projected onto the global horizontal plane. An azimuth of zero
    /// indicates true north with values increasing clockwise. When the sibling
    /// Reference element indicates BODY, azimuth is defined as the angle between
    /// two lines in the plane containing the observer's roll and pitch axis (the
    /// "RP" plane). The first line is from the observation point along the
    /// observer's roll axis or "down the nose" in aircraft terminology. The second
    /// line is from the observation point to the point of interest projected onto
    /// the RP plane. An azimuth of zero indicates directly ahead of the observer
    /// ("down the nose") with values increasing clockwise. An azimuth of Pi/2
    /// indicates directly right of the observer.
    /// xsd type: AngleType
    tl::optional<double> azimuth;  // optional
    /// \brief Indicates the angle from the xy-plane towards the z-axis. When the sibling
    /// Reference element indicates INERTIAL, elevation is defined as the angle
    /// between two lines in a global vertical plane at the observation point. The
    /// first line originates from the observation point and extends along the
    /// azimuth. The second line is from the observation point to the point of
    /// interest. An elevation of zero indicates the point of interest is in the
    /// observation point's horizontal plane. Elevation values are positive when
    /// the point of interest is above the horizontal plane, negative when below.
    /// When the sibling Reference element indicates BODY, elevation is defined as
    /// the angle between two lines in a plane containing the observer's yaw axis.
    /// The first line originates from the observation point and extends along the
    /// azimuth. The second line is from the observation point to the point of
    /// interest. An elevation of zero indicates the point of interest is in the
    /// observer's roll-pitch (RP) plane. Elevation values are positive when the
    /// point of interest is above the RP plane, negative when below.
    /// xsd type: AngleHalfType
    tl::optional<double> elevation;  // optional
};

/// \brief Indicates the Approach Angle either in Azimuth / Elevation or a unit vector
/// relative to the body coordinate system of the target.
/// uci_version: 001.000.000.000
struct ApproachAngleType {
    // oneof choice
    /// \brief Indicates the Azimuth and Elevation of the approach angle.
    tl::optional<AzElReferenceType> az_el;
    /// \brief Indicates a unit vector relative to the coordinate system of the target.
    tl::optional<UnitVectorType> relative;
};

/// \brief Target Final Approach: Altitude defines an altitude relative to the target
/// altitude that the store is commanded to fly at store target final approach
/// range from the target to where it begins terminal maneuvers. Range is a
/// distance from the target location that is determined by the store.
/// uci_version: 001.000.000.000
struct TargetFinalApproachType {
    /// \brief Altitude of store at target final approach.
    /// xsd type: AltitudeType
    tl::optional<double> altitude;  // optional
    /// \brief Distance of store at target final approach.
    /// xsd type: DistanceType
    tl::optional<double> range;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
