/// uci_version: 001.000.000.000
struct ApproachConditionsType {
    /// \brief Indicates the flight mode an allocated store must use to achieve desired
    /// endgame effects.
    tl::optional<StoreFlightModeEnum> flight_mode;  // optional
    /// \brief The distance the weapon needs to travel at the impact angle and the impact
    /// azimuth before hitting the target.
    /// xsd type: DistanceType
    tl::optional<double> range_on_heading;  // optional
    /// \brief Indicates the Approach Angle to the target in either Az/El or a unit vector
    /// relative to the target body coordinate frame.
    tl::optional<ApproachAngleType> approach_angle;  // optional
    /// \brief The final approach to target parameters.
    tl::optional<TargetFinalApproachType> target_final_approach;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 001.000.000.000
struct FuzeTriggerType {
    // oneof choice
    /// \brief Weapon fuze distance setting applies to proximity and hydrostatic fuze
    /// modes. Hydrostatic values will be negative to denote subsurface. Proximity
    /// values will be positive to denote height of burst above ground or distance
    /// to the target depending on the fuze's sensing.
    /// xsd type: DistanceType
    tl::optional<double> fuze_distance;
    /// \brief Weapon fuze delay time setting; applies to impact and time fuze modes.
    /// xsd type: DurationType
    tl::optional<std::string> fuze_delay_time;
};

/// \brief Weapon fuze mode and setting. See operational handbooks and TTP manuals for
/// allowable fuze modes and settings.
/// uci_version: 001.000.000.000
struct FuzeType {
    /// \brief Indicates information for fuze height of burst and fuze delay time.
    FuzeTriggerType fuze_trigger = {};
    /// \brief Fuze modes defined here are derived from operational handbooks and TTP
    /// manuals. Impact is a type of fuze designed to function upon impact or after
    /// delay. The time delay (if any) is measured from the instant of impact. The
    /// proximity fuze is a miniature Doppler radar set. The lag time between
    /// transmission and reception is precomputed and translated into selectable
    /// burst height values in altitude above the target. In a time fuze, the delay
    /// is initiated at bomb release from the aircraft and not at the instant of
    /// impact. The hydrostatic type of fuze is employed in depth bombs for
    /// underwater demolition work.
    tl::optional<WeaponFuzeModeEnum> fuze_mode;  // optional
    /// \brief For weapons with multiple fuzes, indicates which fuze the sibling elements
    /// apply to. Optional for weapons with a single fuze.
    tl::optional<WeaponFuzePositionEnum> fuze_position;  // optional
    /// \brief The name of the fuze.
    /// xsd type: VisibleString1024Type (pattern [ -~]{0,1024})
    std::string mnemonic = {};  // optional
    /// \brief This indicates the time at which the fuze will arm after separating from
    /// the aircraft. Prior to that time, the fuze will not detonate, even if a
    /// fuze trigger is hit. This prevents fragmenting the vehicle if the weapon
    /// blows back into the aircraft or if it is flying very low. Once the fuze
    /// separation arm time elapses, the fuze is armed and the weapon is hot, it
    /// will detonate when the fuze trigger hits.
    /// xsd type: DurationType
    std::string fuze_separation_arm_time = {};  // optional
};

/// \brief Indicates a body face and radial offset.
/// uci_version: 001.000.000.000
struct BodyFaceType {
    /// \brief Indicates the desired face of the body.
    BodyFaceEnum desired_face = BodyFaceEnum::Unspecified;
    /// \brief Indicates a radial offset distance from the center of the face.
    /// xsd type: DistanceType
    tl::optional<double> radial_offset;  // optional
    /// \brief Indicates the angular offset. 0 degrees is aligned with the X axis of the
    /// body face.
    /// xsd type: AnglePositiveType
    tl::optional<double> theta;  // optional
};

/// \brief Specifies an offset vector and an optional location key. See field
/// annotations for more details.
/// uci_version: 000.000.000.000
struct OffsetLocationType {
    /// \brief Offset from the navigational center of the System to the Component in the
    /// forward direction of the System (along the nose of the aircraft for
    /// example), in meters.
    float offset_x = 0.0f;
    /// \brief Offset from the navigational center of the System to the Component in the
    /// right direction (perpendicular to the OffsetX axis when viewed from above
    /// the System, with positive values to the right of the OffsetX axis), in
    /// meters.
    float offset_y = 0.0f;
    /// \brief Offset from the navigational center of the System to the Component in the
    /// down direction (perpendicular to the OffsetX-OffsetY plane, with positive
    /// values toward the bottom of the System), in meters.
    float offset_z = 0.0f;
    /// \brief The Key of the pylon, bay, or other logical location where the Component is
    /// mounted to the host System.
    tl::optional<ForeignKeyType> location_key;  // optional
};

/// \brief Indicates the offset of the component's location as well as the error
/// probability.
/// uci_version: 001.000.000.000
struct OffsetLocationErrorType {
    float offset_x = 0.0f;  // from OffsetLocationType
    float offset_y = 0.0f;  // from OffsetLocationType
    float offset_z = 0.0f;  // from OffsetLocationType
    tl::optional<ForeignKeyType> location_key;  // from OffsetLocationType  // optional
    /// \brief CEP indicates the Circular Error Probable. CEP defines the radius of a
    /// circle of which 50% of the rounds would be expected to land.
    /// xsd type: DistanceType
    tl::optional<double> cep;  // optional
    /// \brief Indicates the confidence of the CEP.
    /// xsd type: PercentType
    tl::optional<double> confidence;  // optional
};

