struct RequirementTemplateOptionType {
    /// \brief Must be unique across options of a Response. When multiple options are
    /// possible, the executable option with the lowest OptionIndex should be
    /// chosen.
    uint32_t requirement_option_index = 0;
    /// \brief Indicates details for a Requirement to generate for this option. Note that
    /// some of the data necessary to generate a Requirement (Effect, Action, Task
    /// or [Capability]Command message) isn't given by this element or sibling
    /// element or elements; it must be inferred/derived from the associated
    /// Option, its triggering event, battlespace context, etc.
    ResponseOptionType requirement = {};
    /// \brief Indicates constraints to apply when generating the sibling Requirement.
    /// Note that some of the data necessary to generate a Requirement's
    /// constraints isn't given by this element or sibling element or elements; it
    /// must be inferred/derived from the associated Response Option and/or its
    /// triggering event, battlespace context, etc. If the sibling Requirement
    /// includes constraints, they override constraints given by this element.
    tl::optional<RequirementConstraintsType> requirement_constraints;  // optional
    /// \brief Indicates additional, complex timing constraints to apply when generating
    /// the sibling Requirement.
    tl::optional<CapabilityCommandTemporalConstraintsType> timing_constraints;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 003.000.003.000
struct RequirementTemplateOptionsType {
    /// \brief Must be unique amongst all Requirements in the template. Allows the
    /// response to be referenced in the sibling DependentRequirement to establish
    /// temporal relationships amongst Requirements.
    uint32_t requirement_index = 0;
    /// \brief Human readable text label with content meaningful to human operators.
    /// xsd type: VisibleString256Type (pattern [ -~]{0,256})
    std::string descriptive_label = {};  // optional
    /// \brief Indicates a potential Requirement to update or generate. When multiple
    /// Requirements are given, only one should be updated/generated. It could be
    /// chosen based on 1) the child RequirementOptionIndex (indicating relative
    /// priority between options), 2) The Capabilities of the System or Systems
    /// available to execute the Requirement or other considerations.
    std::vector<RequirementTemplateOptionType> requirement_option = {};
    /// \brief Indicates a temporal dependency to include when generating or updating the
    /// Requirement selected from the sibling RequirementOption.
    std::vector<RequirementGenerationDependencyType> dependent_requirement = {};
    /// \brief The objective of the collection created as part of this response. List size
    /// for this element is based on "Select All That Apply" condition.
    std::vector<CollectionObjectiveEnum> collection_objective = {};
    /// \brief Maximum allowed product staleness for the product used for Collection
    /// Objective.
    /// xsd type: DurationType
    std::string product_staleness = {};  // optional
};

