/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 001.000.001.000
struct PulseDataCollectCommandType {
    /// \brief Defines the single frequency for the Pulse Data collection to be used for
    /// all dwells defined in the collection.
    CollectionFrequencyType collection_frequency = {};
    /// \brief The requested start time for the subsystem to begin the commanded pulse
    /// data collection.
    /// xsd type: DateTimeType (pattern .+Z)
    std::string start_time = {};
    /// \brief Defines the length of each dwell.
    /// xsd type: DurationType
    std::string dwell_duration = {};
    /// \brief Total number of collect dwells, to include the initial dwell and any
    /// repetitions.
    tl::optional<uint32_t> dwells;  // optional
    /// \brief Time (start-to-start) between dwells.
    /// xsd type: DurationType
    std::string repetition_interval = {};  // optional
    /// \brief Indicates the expected PulseWidth of the desired Pulse.
    /// xsd type: DurationType
    std::string pulse_width = {};  // optional
    /// \brief Indicates the expected PRI of the desired Pulse.
    /// xsd type: DurationType
    std::string pri = {};  // optional
    /// \brief This indicates the estimated bandwidth of the signal being processed.
    tl::optional<FrequencyRangeType> signal_bandwidth;  // optional
    /// \brief This indicates the modulation type to be used for the collection.
    tl::optional<ModulationEnum> modulation;  // optional
    /// \brief Indicates the type of geolocation to be processed.
    tl::optional<SignalTypeEnum> data_collect_type;  // optional
    /// \brief Set the sample rate for the collection, in Hz.
    tl::optional<float> sample_rate;  // optional
    /// \brief Set the number of points per sample that will be used in the Fast Fourier
    /// Transform processing on the collection.
    tl::optional<int32_t> fft_points_per_sample;  // optional
};

