/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 001.000.001.000
struct PathSegmentSpeedType {
    /// \brief Indicates the speed that the vehicle shall traverse the path segment. Speed
    /// can be represented as referenced speed (e.g., ground speed in m/s) or as a
    /// unitless Mach number.
    tl::optional<PathSegmentSpeedChoiceType> speed_choice;  // optional
    /// \brief Indicates that the System will vary its speed autonomously according to the
    /// specified optimization algorithm.
    tl::optional<SpeedOptimizationEnum> speed_optimization;  // optional
};

/// \brief Contains parameters for defining a CAP task
/// uci_version: 000.000.000.000
struct MA_CAP_TaskType {
    /// \brief Defines orbits to be used for CAP task.
    std::vector<MA_OrbitType> orbits = {};
    /// \brief How many assets are to be assigned to each CAP pattern.
    tl::optional<uint32_t> assets_per_orbit;  // optional
    /// \brief Desired priority for MA execution of CAP.
    tl::optional<MA_CAPOptimizationEnum> optimization_strategy;  // optional
    /// \brief Define synchronization scheme across multiple orbits/assets.
    tl::optional<MA_SynchronizationChoiceType> synchronization_strategy;  // optional
    /// \brief References target zone for Keep In boundary for CAP execution.
    std::vector<OpZoneID_Type> keepin_zone_id = {};
    /// \brief References zone that provides threat region of interest information.
    std::vector<OpZoneID_Type> hostile_zone_id = {};
    /// \brief Speed at which CAP should be flown.
    tl::optional<PathSegmentSpeedType> cap_speed;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
