    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> ca_course_to_altitude;
    /// \brief Course to DME Distance Civil Path Terminator Type. This element's children
    /// elements are subject to change over the course of development.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> cd_course_to_dme_distance;
    /// \brief Course to Fix Civil Path Terminator Type. This path terminates at a fixed
    /// point with a specified course at that fix.
    tl::optional<CF_CourseToFixType> cf_course_to_fix;
    /// \brief Course to Intercept Civil Path Terminator Type. This element's children
    /// elements are subject to change over the course of development.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> ci_course_to_intercept;
    /// \brief Course to Radial Civil Path Terminator Type. This element's children
    /// elements are subject to change over the course of development.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> cr_course_to_radial;
    /// \brief Direct to Fix Civil Path Terminator Type. This element's children elements
    /// are subject to change over the course of development.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> df_direct_to_fix;
    /// \brief Track to Altitude Civil Path Terminator Type. This element's children
    /// elements are subject to change over the course of development.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> fa_track_to_altitude;
    /// \brief Track From a Fix to a Distance Along Track Civil Path Terminator Type. This
    /// element's children elements are subject to change over the course of
    /// development.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> fc_track_from_fix_to_distance_along_track;
    /// \brief Track From a Fix to a DME Distance Civil Path Terminator Type. This
