    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> fm_fix_to_manual_termination;
    /// \brief Holding With an Altitude Termination Civil Path Terminator Type. This
    /// element's children elements are subject to change over the course of
    /// development.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> ha_holding_with_altitude_termination;
    /// \brief Holding With a Fix Termination Civil Path Terminator Type. This element's
    /// children elements are subject to change over the course of development.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
    tl::optional<std::string> hf_holding_with_fix_termination;
    /// \brief Holding With a Manual Termination Civil Path Terminator Type. This
    /// element's children elements are subject to change over the course of
    /// development.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
