    tl::optional<std::string> pi_procedure_turn_to_intercept;
    /// \brief Radius to Fix Civil Path Terminator Type. This path is a constant radius
    /// circular path around a defined turn center that terminates at a fixed point.
    tl::optional<RF_RadiusToFixType> rf_radius_to_fix;
    /// \brief Track to Fix Civil Path Terminator Type. This element's children elements
    /// are subject to change over the course of development.
    /// xsd type: EmptyType (pattern [A-Za-z]{0})
