/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct ClimbType {
    /// \brief Indicates the climb rate during this PathSegment.
    /// xsd type: SpeedType
    tl::optional<double> climb_rate;  // optional
    /// \brief Indicates that the system will climb or descend at an autonomously chosen
    /// rate according to the specified optimization algorithm.
    tl::optional<ClimbOptimizationEnum> climb_type;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 002.000.002.000
struct EnduranceRemainingType {
    /// \brief Endurance remaining to be used to compare to the current endurance
    /// remaining.
    EnduranceType endurance_remaining = {};
    /// \brief Logical comparator to use when comparing the current endurance remaining to
    /// the sibling EnduranceRemaining element. The logical expression is (current
    /// endurance remaining) (LogicalOperator) (sibling EnduranceRemaining). When
    /// the logical expression is TRUE then the parent Endurance Condition is TRUE.
    EqualityExpressionEnum logical_operator = EqualityExpressionEnum::Unspecified;
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct SegmentCaptureType {
    /// \brief Capture count to be used to compare to the current capture count.
    uint32_t capture_count = 0;
    /// \brief Logical comparator to use when comparing the current capture count to the
    /// sibling CaptureCount element. The logical expression is (current capture
    /// count) (LogicalOperator) (sibling CaptureCount). When the logical
    /// expression is TRUE then the parent SegmentCapture Condition is TRUE.
    EqualityExpressionEnum logical_operator = EqualityExpressionEnum::Unspecified;
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 002.000.002.000
struct PathSegmentConditionType {
    /// \brief Choose this segment if current altitude (at end of current segment) is in
    /// the specified altitude range.
    tl::optional<AltitudeRangeType> altitude_range;  // optional
    /// \brief Choose this segment if current time (at end of current segment) is in the
    /// specified time window.
    tl::optional<DateTimeRangeType> time_window;  // optional
    /// \brief Choose this segment if the current segment has been captured the specified
    /// number of times.
    tl::optional<SegmentCaptureType> segment_capture;  // optional
    /// \brief If true, only choose this segment if commanded by the operator.
    tl::optional<bool> operator_input;  // optional
    /// \brief Endurance remaining.
    tl::optional<EnduranceRemainingType> endurance;  // optional
    /// \brief Choose this segment if operating in the contingency state specified by this
    /// element.
    tl::optional<SystemContingencyLevelEnum> contingency_level;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 002.000.002.000
struct ConditionalPathSegmentType {
    /// \brief The PathID is included only if branching to a PathSegment defined in an
    /// alternate or contingency path (deviation from primary path).
    tl::optional<PathID_Type> path_id;  // optional
    /// \brief This element indicates the SegmentID of the next PathSegment in the Path.
    /// Any PathSegment of the current Path or other Paths can be referenced.
    SegmentID_Type path_segment_id = {};
    /// \brief This element specifies the condition that will result in this
    /// ConditionalPathSegment being used chosen. A segment shall be chosen as the
    /// next segment when a logical AND of all fields present (except
    /// OperatorInput) equate to TRUE.
    tl::optional<PathSegmentConditionType> condition;  // optional
};

/// \brief Defines details of orbit loiter
/// uci_version: 000.000.200.000
struct MA_HoldLegSpecificationType {
    // oneof choice
    /// \brief Duration to fly the inbound leg in seconds.
    /// xsd type: DurationType
    tl::optional<std::string> leg_time;
    /// \brief Length to fly the inbound leg in meters.
    /// xsd type: DistanceType
    tl::optional<double> leg_length;
};

/// \brief Specifies the turns of the hold.
/// uci_version: 000.000.000.000
struct MA_HoldTurnSpecificationType {
    // oneof choice
    /// \brief Radius of the hold turns in meters.
    /// xsd type: DistanceType
    tl::optional<double> turn_radius;
    /// \brief Turn rate at which the hold turns are to be executed in radians per second.
    /// xsd type: AngleRateType
    tl::optional<double> turn_rate;
    /// \brief Specification of the type of turn to be executed during the hold.
    tl::optional<MA_HoldTurnTypeEnum> turn_type;
};

/// \brief Specifies the turns of the hold.
/// uci_version: 000.000.000.000
struct MA_OrbitDurationType {
    // oneof choice
    /// \brief Radius of the hold turns in meters.
    /// xsd type: DurationType
    tl::optional<std::string> time;
    /// \brief Turn rate at which the hold turns are to be executed in radians per second.
    tl::optional<uint32_t> number_of_orbits;
    /// \brief Required time(s) to enter and/or exit the hold.
    tl::optional<DateTimeRangeType> entry_exit_time;
};

/// \brief Defines details of orbit loiter
/// uci_version: 000.000.000.000
struct MA_HoldType {
    /// \brief Point at which inbound leg of hold ends.
    Point2D_Type anchor_point = {};
    /// \brief Operational context for the hold used to determine the appropriate default
    /// parameters necessary to define the hold.
    tl::optional<MA_HoldContextEnum> hold_context;  // optional
    /// \brief Indicates the speed to maintain during the hold pattern.
    tl::optional<PathSegmentSpeedType> speed;  // optional
    /// \brief Orientation of the hold, defined as the course along the inbound leg.
    /// xsd type: AngleType
    tl::optional<double> orientation;  // optional
    /// \brief Direction of turn when rounding the first loiter point.
    tl::optional<RelativeDirectionEnum> turn_direction;  // optional
    /// \brief Specifies the length of the hold based on the inbound leg.
    MA_HoldLegSpecificationType leg_specification = {};
    /// \brief Specifies the turns of the hold.
    MA_HoldTurnSpecificationType turn_specification = {};
    /// \brief Specifies the duration of the hold.
    MA_OrbitDurationType duration = {};
    /// \brief Specified method for entering the hold.
    MA_HoldEntryTypeEnum entry_type = MA_HoldEntryTypeEnum::Unspecified;
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct MA_LoiterType {
    // oneof choice
    /// \brief The details of an orbit loiter.
    tl::optional<MA_OrbitType> orbit;
    /// \brief The details of a hover loiter.
    tl::optional<HoverType> hover;
    /// \brief The details of a hold loiter.
    tl::optional<MA_HoldType> hold;
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct MA_LoiterPointType {
    /// \brief The geospatial loiter details.
    MA_LoiterType loiter = {};
    /// \brief Indicates the time at which the loiter will end.
    /// xsd type: DateTimeType (pattern .+Z)
    std::string end_time = {};  // optional
};

/// \brief This element is used to specify all cases of turns in a segment including
/// fly-through and turn-short. TurnPoints will generally come in groups of at
/// least two in linked PathSegments. All but the last in a group will include
/// a TurnRadius.
/// uci_version: 002.001.002.001
struct TurnPointType {
    /// \brief This element indicates the location and time of arrival of the end of the
    /// path segment.
    WayPointPointChoiceType waypoint = {};
    /// \brief Represents the desired behavior at the associated way point.
    TurnPointTypeEnum turn_point_type = TurnPointTypeEnum::Unspecified;
    /// \brief Indicates the course at the Waypoint of this TurnPoint.
    /// xsd type: AngleType
    tl::optional<double> course;  // optional
    /// \brief Indicates the bank angle or radius of the turn. When Turn Geometry is not
    /// specified, indicates that the TurnPoint is in the end of a turn.
    tl::optional<TurnGeometryChoiceType> turn_geometry;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct MA_EndPointType {
    // oneof choice
    /// \brief This element is used to specify a point in the route where no turning
    /// occurs. It is generally used for points associated with Actions such as
    /// task "transitions", changes in acceleration, changes in speed, changes in
    /// altitude, etc.
    tl::optional<WayPointType> way_point;
    /// \brief This element is used to specify all cases of turns in a segment including
    /// fly-through and turn-short. It can additionally be associated with
    /// tasks/actions that require or are coincident with turns. TurnPoints will
    /// generally come in groups of at least two in linked PathSegments. All but
    /// the last in a group will include a TurnRadius.
    tl::optional<TurnPointType> turn_point;
    /// \brief This element specifies a Loiter. Currently specifying a task/action
    /// associated with a LoiterPoint when the task/action occurs only during a
    /// portion of the Loiter is not supported.
    tl::optional<MA_LoiterPointType> loiter_point;
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 001.000.000.000
struct NextPathSegmentType {
    /// \brief Indicates the PathID of the Path containing the next PathSegment. It is
    /// only required when branching to a PathSegment in a Path other than the
    /// parent Path of the current PathSegment.
    tl::optional<PathID_Type> path_id;  // optional
    /// \brief This element indicates the PathSegmentID of the next PathSegment in the
    /// Path.
    SegmentID_Type path_segment_id = {};
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct MA_PathSegmentType {
    /// \brief Indicates the unique ID for this PathSegment. Other Paths or PathSegments
    /// may branch to this path segment by referring to this ID.
    SegmentID_Type path_segment_id = {};
    /// \brief Defines whether the path segment was manually defined or if it was defined
    /// by an operator. This element can be used for many reasons including, but
    /// not limited to, operator display.
    PathSegmentSourceEnum source = PathSegmentSourceEnum::Unspecified;
    /// \brief Indicates the end point of the PathSegment. The start point is the end
    /// point of the previous PathSegment.
    MA_EndPointType end_point = {};
    /// \brief This flag is used to determine whether the segment can be modified/removed
    /// or was driven by an operator and therefore cannot be modified.
    tl::optional<bool> locked;  // optional
    /// \brief If this element is present and set to TRUE, this PathSegment has been
    /// modified as part of a MODIFIED_ROUTE MissionPlan. This data is valuable to
    /// some planning algorithms to support validation of a user modified route.
    tl::optional<bool> modified;  // optional
    /// \brief Indicates the speed or speed optimization of the System along the
    /// PathSegment at the EndPoint.
    tl::optional<PathSegmentSpeedType> speed;  // optional
    /// \brief Defines the Civil Path Terminator information associated with the End Point.
    tl::optional<CivilPathTerminatorType> civil_path_terminator;  // optional
    /// \brief Indicates whether the vehicle shall climb/descend and at what rate while
    /// traversing the path segment.
    tl::optional<ClimbType> climb;  // optional
    /// \brief Indicates the maximum roll allowed along the PathSegment. Angle in radians
    /// representing vehicle's rotation about the longitudinal axis (the axis
    /// through the body of the vehicle from tail to nose) in a locally level,
    /// North-East-Down coordinate system centered on the vehicle. Roll is zero
    /// when the aircraft is wing-tip to wing-tip level in the North-East plane.
    /// xsd type: AngleType
    tl::optional<double> maximum_roll;  // optional
    /// \brief Indicates the acceleration of the System along the PathSegment at the
    /// EndPoint.
    /// xsd type: AccelerationType
    tl::optional<double> acceleration;  // optional
    /// \brief This element is used to specify the next non-conditional PathSegment. This
    /// path segment can be the next segment in the current path or can be a
    /// transitional segment to another Path defined by the PathID. If the PathID
    /// is specified and differs from the current PathID, then this signals the end
    /// of the current Path and a transition to another Path. If no NextPathSegment
    /// is given then this is the end of the Route.
    tl::optional<NextPathSegmentType> next_path_segment;  // optional
    /// \brief This element is used to specify one or more conditional PathSegment.
    std::vector<ConditionalPathSegmentType> conditional_path_segment = {};
    /// \brief This element is intended to provide detailed inertial state information at
    /// user defined increments within a path segment. This element provides data
    /// which may be required for pre-mission analysis of a Route. Position data
    /// may be specified as either a geospatial point or relative to a separately
    /// defined reference frame.
    std::vector<InertialStateRelativeType> inertial_state = {};
    /// \brief Describes the mission planned required time of arrival. This message allows
    /// the operator to see a delta between the required and estimated arrival
    /// times that would allow for speed up/slow down determinations. This field is
    /// used as a constraint on the timing of the waypoint.
    tl::optional<TimeWindowType> required_time_of_arrival;  // optional
    /// \brief Indicates information about the path segment from an operator that is
    /// intended for display. Both short and longer detailed information can be
    /// provided.
    tl::optional<RemarksType> remarks;  // optional
    /// \brief Specifies the navigation performance accuracy required in an airspace. This
    /// value is in meters rather than the RNP standard of nautical miles.
    /// xsd type: DistanceType
    tl::optional<double> required_navigation_performance_in_meters;  // optional
    /// \brief Specifies a geographical position determined by visual reference to the
    /// surface, by reference to one or more radio NAVAIDs, by celestial plotting
    /// or another navigational device.
    tl::optional<ForeignKeyType> fix_identifier;  // optional
};

/// \brief The ID type for UCI IDs that correspond to runways.
