struct RunwayID_Type {
    std::string uuid = {};  // from ID_Type
    std::string descriptive_label = {};  // from ID_Type  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct MA_RoutePathType {
    /// \brief Indicates the unique ID for this Path. Other Paths or PathSegments may
    /// branch to this path by referring to this ID.
    PathID_Type path_id = {};
    /// \brief Indicates which path type is defined in this path object.
    MA_PathTypeEnum path_type = MA_PathTypeEnum::Unspecified;
    /// \brief Indicates the unique ID of the first PathSegment of the Path.
    SegmentID_Type first_in_path_segment_id = {};
    /// \brief A PathSegment is defined from the previous path segment EndPoint (or
    /// current vehicle state if no previous path segment) to the current path
    /// segment EndPoint. Elements given here are not necessarily in mission/flight
    /// order; it is necessary to follow the linkages provided in NextPathSegment
    /// and/or ConditionalPathSegment to traverse the segments in mission/flight
    /// order.
    std::vector<MA_PathSegmentType> path_segment = {};
    /// \brief Indicates planned or assessed initial conditions of the vehicle at the
    /// beginning of the Path.
    tl::optional<PlanningLocationType> initial_conditions;  // optional
    /// \brief Indicates the Airfield message containing the Runway information.
    tl::optional<AirfieldID_Type> airfield_id;  // optional
    /// \brief Indicates the runway at which this path is either taking off or landing.
    tl::optional<RunwayID_Type> runway_id;  // optional
    /// \brief Indicates information about the path from an operator that is intended for
    /// display. Both short and longer detailed information can be provided.
    tl::optional<RemarksType> remarks;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 000.000.000.000
struct MA_RouteType {
    /// \brief Indicates whether the route is the result of detailed mission planning
    /// (TRUE), or is a simple stick route (FALSE).
    bool detailed = false;
    /// \brief Indicates the unique ID of the first Path of the Route. The first Path of
    /// the Route would generally be of PRIMARY PathType.
    PathID_Type first_in_route_path_id = {};
    /// \brief Indicates which line/curve generation type was used to define the route.
    LineProjectionEnum route_projection = LineProjectionEnum::Unspecified;
    /// \brief A series of path segments. A route can contain many paths. Some paths
    /// provide alternate routes and contingency routes which branch from the
    /// primary path. Other paths can be standalone, disconnected paths. Elements
    /// given here are not necessarily in mission/flight order; it is necessary to
    /// follow the linkages provided in NextPathSegment and/or
    /// ConditionalPathSegment to traverse the segments in mission/flight order.
    std::vector<MA_RoutePathType> path = {};
    /// \brief Indicates information about the route from an operator that is intended for
    /// display. Both short and longer detailed information can be provided.
    tl::optional<RemarksType> remarks;  // optional
};

