    /// \brief Indicates a Task to a jettisonable weapon from the system.
    tl::optional<MA_JettisonTaskType> jettison;
    /// \brief Indicates a task to perform an orbit change via a spacecraft maneuver.
    tl::optional<OrbitChangeTaskType> orbit_change;
    /// \brief Indicates an Orbital Surveillance Task.
    tl::optional<OrbitalSurveillanceTaskType> orbital_surveillance;
    /// \brief Indicates a task to perform orbital surveillance sensor tasking.
    tl::optional<OrbitalSurveillanceSensorTaskType> orbital_surveillance_sensor;
    /// \brief Indicates a Task to collect Passive Optical data, imagery and video as well
    /// as perform PO search and track capabilities.
    tl::optional<PO_TaskType> po;
    /// \brief Indicates a Task for one System to refuel another.
    tl::optional<RefuelTaskType> refuel;
    /// \brief Indicates a Task to collect a Synthetic Aperture Radar (SAR) image.
    tl::optional<SAR_TaskType> sar;
    /// \brief Indicates a Task to collect Moving Target Indicator (MTI) data.
    tl::optional<SMTI_TaskType> smti;
    /// \brief Indicates a Task to kinetically attack/strike, with a weapon that can be
