/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 001.000.002.000
struct ConflictType {
    /// \brief Unique ID for this conflict.
    ID_Type conflict_id = {};
    /// \brief The object that is causing the conflicted system to be in a contingency
    /// state. This item is optional if and only if the conflicting object is not
    /// known. For example, when a FAILED Task is received by a parent system
    /// (FAILED task state is used to escalate the issue to the parent node). This
    /// may generate a contingency alert at the parent node where the conflicting
    /// object is unknown. In other words, a parent system receives a FAILED Task,
    /// but doesn't necessarily know why the Task has failed. This could cause the
    /// parent system to generate an alert with a sibling AffectedRequirement
    /// without a ConflictingObject.
    tl::optional<ID_Type> conflicting_object_id;  // optional
    /// \brief This is the first location along the planned route where the conflict will
    /// occur. This data is optional and primarily applies to conflicts with pop-up
    /// threats or zones where the conflict occurs at a future point along the
    /// route. It is not expected that this data will be populated for Capability
    /// and other System failures which affect a System's ability to perform its
    /// assigned Tasking. The primary intent of this data is for display purposes
    /// to provide operator SA.
    tl::optional<ConflictLocationType> conflict_location;  // optional
    /// \brief Indicates the time window in which the conflict is expected to occur.
    tl::optional<DateTimeRangeType> conflict_time;  // optional
    /// \brief Indicates the ID of Requirement or Requirements which can no longer be
    /// performed due to the effect of the conflicting object. IDs are given if and
    /// only if they can no longer be accomplished with the current mission plans.
    /// As a result, a contingency generated by a pop-up threat (or other
    /// environment change) might be handled via a simple reroute which does not
    /// affect any Requirements. Alternatively, if a Capability fails, affected
    /// Requirements are more likely known and should be included in this element.
    /// A Service would only list the Requirements if the Service KNOWS there is a
    /// problem with it. For example, a Service should not populate this value with
    /// all Tasks in an affected MissionPlan simply because it is uncertain as to
    /// the effect of a reroute on the associated Tasks.
    tl::optional<RequirementsReferenceType> affected_requirements;  // optional
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 003.000.003.000
struct MissionContingencyConditionType {
    /// \brief This is the ID of the system that has the contingency condition. In most
    /// route related conflicts, this will be populated with a vehicle's SystemID.
    /// In task allocation conditions, this may be a System or control node
    /// SystemID.
    SystemID_Type conflicted_system_id = {};
    /// \brief Indicates whether the conflict is still affecting the conflicted system or
    /// has been resolved (either autonomously or by the operator) or OBE.
    ConflictStateEnum conflict_state = ConflictStateEnum::Unspecified;
    /// \brief This element provides details of the contingency condition. Most elements
    /// within are optional because of the many different cases that this element
    /// is intended to represent. However, the requirements for describing a
    /// conflict are the following: 1. ConflictingObject is required if known. 2.
    /// AffectedRequirements are required if and only if it is known that a task
    /// can no longer be performed. 3. ConflictLocation primarily applies to route
    /// conflicts. This data is primarily for operator SA.
    std::vector<ConflictType> conflict = {};
    /// \brief Indicates the autonomy trigger (from PlanningFunction*) which triggered the
    /// alert.
    tl::optional<PlanningTriggerType> trigger;  // optional
    /// \brief Indicates the status of the autonomous planning action or actions
    /// addressing the conflict.
    tl::optional<AutonomousActionStatusChoiceType> autonomous_action_status;  // optional
    /// \brief This element can be provided when autonomy settings dictate that autonomous
    /// correction of a problem is not allowed or when a system does not have
    /// autonomous contingency correction capability. Multiple instances allow a
    /// series of actions to be specified to address the contingency condition.
    /// Order is implied by the order in which elements are included in the
    /// message. For example, to resolve a contingency associated with a failed
    /// Capability, the series of actions might be: 0. Drop Tasks 1. Reallocate
    /// Dropped Tasks.
    std::vector<OperatorRecommendationType> operator_recommendation = {};
};

/// \brief See annotations in child elements and messages/elements that use this type
/// for details.
/// uci_version: 003.000.003.000
struct MissionContingencyAlertMDT {
    /// \brief The unique identifier for this mission contingency alert.
    MissionContingencyAlertID_Type mission_contingency_alert_id = {};
    /// \brief This is the ID of the system that detects the contingency and is generating
    /// the alert. In a hierarchy of systems, not all children systems may have
    /// Contingency Management service functionality. As a result, the Source
    /// System may be a parent of the system that has the contingency condition.
    SystemID_Type source_system_id = {};
    /// \brief This element is intended to capture contingency conditions identified by
    /// the impacted system. The ID references and elements herein are intended to
    /// complete the following statement: ConflictedSystem S1 has a conflict
    /// (contingency) caused by ConflictingObject X at ConflictLocation Y. As a
    /// result, AffectedTaskID Z can no longer be performed. The Contingency
    /// Management function has identified this as AutonomyCase AC1 and either: 1.
    /// Autonomy is allowed and the system is addressing the contingency. 2.
    /// Autonomy is not allowed and the Contingency Management function recommends
    /// that the operator perform certain actions to resolve the condition.
    std::vector<MissionContingencyConditionType> contingency_condition = {};
};

/// \brief See the annotation in the associated message for an overall description of
/// the message and this type.
/// uci_version: 003.000.003.000
struct MissionContingencyAlertMT {
    SecurityInformationType security_information = {};  // from MessageType
    HeaderType message_header = {};  // from MessageType
    /// \brief Indicates the state of the internal software object that the data in the
    /// message is based upon. The state of the software object is determined by
    /// the publisher. The publisher could be the original/master publisher or an
    /// intermediary re-publisher such as a persistence/data manager. This element
    /// is not a commanded CRUD operation. It is not an indication of the state of
    /// an instance of a message. It is not a mechanism for partial, incremental,
    /// or fragmentary publication of a message. It is a signal from a publisher to
    /// subscribers. For REMOVED state, in particular, some subscribers will mirror
    /// the publisher and treat the message as if the object no longer exists, but
    /// others, such as mission recorders, might not (in order to support retaining
    /// historical records of activity, for example).
    tl::optional<ObjectStateEnum> object_state;  // optional
    /// \brief See annotations in child elements and messages/elements that use this type
    /// for details.
    MissionContingencyAlertMDT message_data = {};
};

